    var timeoutMs=apiTimeoutMs(opt);
    var tmr=setTimeout(function(){timedOut=true;ctrl.abort()},timeoutMs);
    var heartbeat=setInterval(function(){
      try{if(typeof opt.onHeartbeat==='function')opt.onHeartbeat()}catch(_){}
      try{if(typeof opt.extraCheck==='function')opt.extraCheck()}catch(_2){}
    },Math.max(5000,Number(opt.heartbeatMs||20000)||20000));
    var slowTimer=setTimeout(function(){try{if(typeof opt.onSlow==='function')opt.onSlow({model:model,elapsedMs:30000})}catch(_slow){}},30000);
    if(opt.abortKey)app[opt.abortKey]=ctrl;
