      var r=await fetch(url,{method:'POST',headers:{'Content-Type':'application/json','Authorization':'Bearer '+key},body:JSON.stringify({model:model,messages:[{role:'user',content:String(prompt||'')}],temperature:opt.temperature==null?0.2:opt.temperature,max_tokens:opt.max_tokens||2200,stream:false}),signal:ctrl.signal});
