        var bodyText='',bodyObj=null;
        try{bodyText=await r.text()}catch(_body){}
        if(bodyText){try{bodyObj=JSON.parse(bodyText)}catch(_json){}}
        throw apiError(r.status,bodyText,bodyObj);
      }
      var d=await r.json();
      var text=extractApiText(d);
      if(!trim(text)){
        var empty=new Error('API 返回成功但没有正文：'+(describeApiEmpty(d)||'响应结构不含正文'));
        empty.code='empty_response';
        throw empty;
      }
      if(typeof opt.onSuccess==='function')try{opt.onSuccess({model:model})}catch(_ok){}
      return trim(text);
    }catch(e){
      if(e&&e.name==='AbortError'&&timedOut){
        var timeout=new Error('API 请求超时：超过 '+Math.round(timeoutMs/1000)+' 秒未返回');
        timeout.code='api_timeout';
        e=timeout;
      }
      if(!retryableApiError(e)||i===maxRetries){
        if(typeof opt.onError==='function')try{opt.onError(e,{model:model,attempt:i})}catch(_err){}
        throw e;
      }
