async function collectRange(fromL,toL,opt){

  opt=opt||{};

  var providedMessages=opt.messages&&Array.isArray(opt.messages)?opt.messages:null;

  var msgs=providedMessages?providedMessages:null;

  var idx=opt.index&&typeof opt.index==='object'?normalizeMessageIndex(opt.index):await getMessageIndex({force:!!opt.forceIndex,save:!!opt.save});

  var slots=idx.slots||[];

  if(opt.save){try{var s=app.state||await load();s.messageIndex=idx;await save(s)}catch(_){}}

  var names=opt.names||await getNames();

  fromL=Math.max(1,Number(fromL)||1);

  toL=Math.max(fromL,Number(toL)||fromL);

  if(!slots.length||fromL>slots.length)return{messages:[],startL:fromL,endL:toL,names:names,truncated:false,messageIndex:idx,slots:[]};

  toL=Math.min(toL,slots.length);

  var openingEnd=Number(idx.firstAssistantSourceIndex==null?-1:idx.firstAssistantSourceIndex);

  var start=fromL>1?slots[fromL-2].index+1:Math.max(0,openingEnd+1);

  var end=slots[toL-1].index;

  if(!msgs){
    msgs=await callTavo(function(){return TV.message.find([start,end])},'message.find.range',12000,{silent:true,fallback:[]});
    msgs=Array.isArray(msgs)?msgs.filter(Boolean):[];
  }

  var out=[];

  var loopStart=providedMessages?start:0;

  var loopEnd=providedMessages?Math.min(end,msgs.length-1):(msgs.length-1);

  for(var i=loopStart;i<=loopEnd;i++){

    var m=msgs[i];
    var sourceIndex=providedMessages?i:(start+i);
    /* 不再跳过 m.hidden===true（隐藏楼层总结时也要抓）。
       只跳过 system 消息和插件自身文本。 */
    if(!m||m.role==='system'||isPluginAssistantText(messageContent(m)))continue;

    if(m.role!=='assistant'&&m.role!=='user')continue;

    var l=assistantLAt(slots,sourceIndex);

    var id=messageIdOf(m);

    out.push({index:sourceIndex,sourceIndex:sourceIndex,line:sourceIndex+1,L:m.role==='assistant'?l:Math.max(fromL,l+1),floorL:m.role==='assistant'?l:Math.max(fromL,l+1),messageId:id,id:id,role:m.role,speaker:m.role==='user'?names.userName:names.charName,characterId:m.characterId||null,content:messageContent(m),time:m.created_at||m.createdAt||m.timestamp||m.time||'',message:m,msg:m});

  }

  return{messages:out,startL:fromL,endL:toL,startIndex:start,endIndex:end,names:names,truncated:false,messageIndex:idx,slots:resolveRange(fromL,toL,idx)};

}

