  opt=opt||{};var pc=platformCore();if(!pc||!pc.callAPI)throw makeError('local_generate_unavailable','当前没有可用的生成接口','platformCore.callAPI 不可用');
  var s=app.state||await load();var cfg=effectiveApiSettings(s);var model=trim(cfg.apiModel||opt.model||'gpt-4o-mini')||'gpt-4o-mini';
  var apiStart=now();
  addLogToState(s,'正在请求模型','running','模型：'+model,null,{step:'requesting_model'});
  try{await save(s)}catch(_){}
  try{
    var text=await pc.callAPI(prompt,Object.assign({},opt,{temperature:opt.temperature==null?0.15:opt.temperature,apiSettings:cfg,onHeartbeat:function(){touchModelWaitState(s);save(s).catch(function(){})},onSlow:function(){try{addLogToState(s,'接口响应较慢','ok','已等待 30 秒，请保持前台。');save(s).catch(function(){})}catch(_slow){}},onRetry:function(e,ctx){addLogToState(s,'API 请求重试','err','第 '+(Number(ctx&&ctx.attempt||0)+1)+' 次没成功，正在自动重试。原因：'+userErrorMessage(e),e,{step:'requesting_model',code:classifyError(e),devDetail:errDetail(e)});save(s).catch(function(){})}}));
    resolveRunningLog(s,'正在请求模型','模型：'+model,'模型已返回','ok','耗时 '+(now()-apiStart)+'ms');
    try{await save(s)}catch(_){}
    return trim(text);
  }catch(e){
    resolveRunningLog(s,'正在请求模型','模型：'+model,e&&e.name==='AbortError'?'请求中断':'请求失败','err',userErrorMessage(e),e);
    try{await save(s)}catch(_){}
    throw e;
  }
}



async function generateText(prompt,opt){

  opt=opt||{};var s=app.state||await load();var apiErr=null;var cfg=effectiveApiSettings(s);

  if(trim(cfg.apiBaseUrl)&&trim(cfg.apiKey)){try{return await callAPI(prompt,opt)}catch(e){if(e&&e.name==='AbortError')throw e;apiErr=e}}

  if(T.tavo&&T.tavo.generate){var localText=trim(await T.tavo.generate(prompt,{context:false}));if(localText)return localText;if(apiErr)throw apiErr;throw makeError('empty_response','模型没有返回可用内容','Tavo 本地生成返回为空')}

  if(apiErr)throw apiErr;throw makeError('local_generate_unavailable','当前没有可用的生成接口','没有 API 配置，也没有检测到 Tavo generate');

}



function retryableGenerateError(e){if(e&&e.name==='AbortError')return false;return retryableApiError(e)}




async function generateTextRetry(prompt,opt,s,label){


  opt=opt||{};var tries=opt.retries==null?2:Math.max(0,Number(opt.retries)||0);var lastErr=null;
  for(var i=0;i<=tries;i++){


    try{return await generateText(prompt,opt)}catch(e){

      lastErr=e;if(e&&e.name==='AbortError')throw e;

      if(!retryableGenerateError(e)||i>=tries)throw e;

      if(s){if(s.scan)s.scan.lastActiveAt=now();addLogToState(s,(label||'生成')+'重试','err','第 '+(i+1)+' 次没成功，正在重试。原因：'+userErrorMessage(e),e,{step:'requesting_model',code:classifyError(e),devDetail:errDetail(e)})}

      try{await save(s||app.state)}catch(_){}

      await new Promise(function(resolve){setTimeout(resolve,700*(i+1))});

    }

  }


  throw lastErr;


}





