function buildTranscript(bundle){


  return safeArr(bundle.messages).map(function(m){


    var label=m.speakerTag||(m.speaker||'');


    return'['+m.L+'L'+(m.time?'｜'+m.time:'')+'｜'+label+'] '+m.content;


  }).join('\n');


}





function buildMarksSection(s,fromL,toL){
  var marks=active(s.marks).filter(function(mk){return mk.L>=fromL&&mk.L<=toL&&!mk.processed});


  if(!marks.length)return'';


  var lines=['用户在以下楼层做了手动标记，请优先关注这些位置：'];


  marks.forEach(function(mk){


    var parts=[mk.L+'L'];


    if(mk.type&&mk.type!=='general')parts.push('类型：'+mk.type);


    if(mk.boundary==='start')parts.push('用户认为这是一个事件的起点');


    if(mk.boundary==='end')parts.push('用户认为这是一个事件的终点');


    if(mk.note)parts.push('备注：'+mk.note);


    if(mk.emotionTags.length)parts.push('情绪：'+mk.emotionTags.join('、'));


    lines.push('- '+parts.join('｜'));


  });


  return lines.join('\n');
}

function buildAlreadyEventsSection(s,fromL,toL){
  var list=active(s.events).filter(function(ev){
    var a=Number(ev.startL||0)||0,b=Number(ev.endL||0)||0;
    return a<=toL&&b>=fromL;
  }).map(function(ev){return{title:clip(ev.title||'',30),startL:Number(ev.startL||0)||0,endL:Number(ev.endL||0)||0}}).slice(0,20);
  return list.length?JSON.stringify(list):'[]';
}

async function loadMemoCoverageMap(fromL,toL){
  try{
    var p=platformApp(),memo=p&&p.plugins&&p.plugins.memo;
    if(memo&&typeof memo.getCoverageMap==='function')return memo.getCoverageMap(fromL,toL);
  }catch(_){}
  try{
    var m=T.__FIFTH_SEASON_MEMO__;
    if(m&&m.core&&typeof m.core.getCoverageMap==='function')return m.core.getCoverageMap(fromL,toL);
  }catch(_){}
  return null;
}
function buildMemoCoverageSection(map){
  if(!map||!map.hasCoverage)return'[]';
  var out=[];
  safeArr(map.historyOverview?[map.historyOverview]:[]).forEach(function(x){if(x)out.push(x)});
  safeArr(map.longTerms).forEach(function(x){out.push(x)});
  safeArr(map.summaries).forEach(function(x){out.push(x)});
  return JSON.stringify(out.slice(0,24).map(function(x){return{type:x.type,startL:Number(x.startL||0)||0,endL:Number(x.endL||0)||0,title:clip(x.title||'',48),stale:!!x.stale}}));
}

