      if(c==='"'){inStr=true;continue}
      if(c==='{'||c==='['){stack.push(c);continue}
      if(c==='}'||c===']'){
        var last=stack[stack.length-1];
        if((c==='}'&&last!=='{')||(c===']'&&last!=='['))break;
        stack.pop();
        if(!stack.length){if(cb(text.slice(start,i+1),start,i+1)===false)return;break}
