function buildWindows(fromL,toL,settings){


  var windowSize=Math.max(6,Number(settings.scanWindowSize||20)||20);


  var overlap=Math.max(0,Number(settings.scanOverlap||4)||4);


  fromL=Math.max(1,Number(fromL)||1);toL=Math.max(fromL,Number(toL)||fromL);


  var out=[];var cursor=fromL;


