}





function rangeOverlapRatio(aStart,aEnd,bStart,bEnd){var inter=Math.max(0,Math.min(aEnd,bEnd)-Math.max(aStart,bStart)+1);var lenA=Math.max(1,aEnd-aStart+1);var lenB=Math.max(1,bEnd-bStart+1);return inter/Math.min(lenA,lenB)}


function eventTextSimilar(a,b){


  var at=sig((a&&a.title||'')+' '+(a&&a.summary||''));var bt=sig((b&&b.title||'')+' '+(b&&b.summary||''));


  if(at&&bt&&(at.indexOf(bt)>=0||bt.indexOf(at)>=0))return true;


  var aq=safeArr(a&&a.rawQuotes).map(sig).filter(Boolean);var bq=safeArr(b&&b.rawQuotes).map(sig).filter(Boolean);


  for(var i=0;i<aq.length;i++){for(var j=0;j<bq.length;j++){if(aq[i]&&bq[j]&&(aq[i]===bq[j]||aq[i].indexOf(bq[j])>=0||bq[j].indexOf(aq[i])>=0))return true}}


  if(a&&b&&a.sourceHash&&b.sourceHash&&String(a.sourceHash)===String(b.sourceHash))return true;


  return false;


}


function hasOverlappingEvent(s,startL,endL,candidate){
  return active(s.events).some(function(ev){
    var es=Number(ev.startL||0),ee=Number(ev.endL||0);
    if(es===startL&&ee===endL)return true;
    if(rangeOverlapRatio(es,ee,startL,endL)<0.6)return false;
    return !candidate||eventTextSimilar(ev,candidate);
  });
}
function acceptEventByOverlapPolicy(s,candidate){
  var ns=Number(candidate&&candidate.startL||0)||0,ne=Number(candidate&&candidate.endL||0)||0;
  var overlaps=active(s.events).filter(function(ev){var es=Number(ev.startL||0)||0,ee=Number(ev.endL||0)||0;return ns<=ee&&ne>=es});
  if(!overlaps.length)return true;
  var containsOld=overlaps.every(function(ev){return ns<=Number(ev.startL||0)&&ne>=Number(ev.endL||0)});
  if(containsOld){
    overlaps.forEach(function(ev){
      safeArr(ev.sourceMarkIds||ev.source_mark_ids).forEach(function(id){candidate.sourceMarkIds=addUniqueId(candidate.sourceMarkIds,id)});
      active(s.marks).forEach(function(mk){
        if(mk.linkedEventId===ev.id){
          mk.linkedEventId=candidate.id||'';
          mk.linkedTitle=candidate.title||mk.linkedTitle||'';
          mk.updatedAt=now();
        }
      });
      active(s.moments).forEach(function(mo){if(mo.linkedEventId===ev.id){mo.linkedEventId=candidate.id||'';mo.updatedAt=now()}});
      ev.deleted=true;ev.updatedAt=now();ev._replacedBy=candidate.id||''
    });
    return true;
  }
  return false;
}
function avoidRecentForm(form,s,localEvents,ev){
  form=normForm(form)||chooseEventForm(ev||{});


  var recent='';


  var local=safeArr(localEvents).filter(Boolean);


  if(local.length)recent=local[local.length-1].form;


  if(!recent){


    var prev=active(s&&s.events).sort(function(a,b){return(Number(b.endL||0)||0)-(Number(a.endL||0)||0)})[0];


    recent=prev&&prev.form||'';


  }


  if(recent!==form)return form;


  var idx=RECALL_FORMS.indexOf(form);if(idx<0)return form;


  var h=Math.abs(Number(hashText((ev&&ev.title||'')+'|'+(ev&&ev.summary||'')))||0);


  return RECALL_FORMS[(idx+1+h) % RECALL_FORMS.length]||form;


}





function resolveFailedRangesByCoverage(s,startL,endL){
  s.failedRanges=safeArr(s.failedRanges).map(function(x){
    if(!x||x.resolved)return x;
    if(startL<=Number(x.startL||0)&&endL>=Number(x.endL||0))x.resolved=true;
    return x;
  });
}

function addUniqueId(list,id){id=trim(id);if(!id)return safeArr(list);list=safeArr(list);if(list.indexOf(id)<0)list.push(id);return list}

function linkMarksInRange(s,fromL,toL){
  var marks=active(s.marks).filter(function(mk){var L=Number(mk.L||0)||0;return L>=fromL&&L<=toL});
  marks.forEach(function(mk){
    var L=Number(mk.L||0)||0;if(!L)return;
    var matchedEvent=active(s.events).find(function(ev){return L>=Number(ev.startL||0)&&L<=Number(ev.endL||0)});
    if(matchedEvent){
      mk.linkedEventId=matchedEvent.id;mk.linkedTitle=matchedEvent.title||mk.linkedTitle||'';
      matchedEvent.sourceMarkIds=addUniqueId(matchedEvent.sourceMarkIds,mk.id);
    }
    var matchedMoments=active(s.moments).filter(function(m){return Number(m.L||0)===L});
    if(matchedMoments.length){
      mk.linkedMomentIds=matchedMoments.map(function(m){m.sourceMarkIds=addUniqueId(m.sourceMarkIds,mk.id);return m.id});
    }
    if(matchedEvent||matchedMoments.length){mk.processed=true;mk.updatedAt=now()}
  });
  return marks.length;
}



async function acquireHeavyLock(runId){


  var existing=rawGet(HEAVY_LOCK_KEY,'global');var ts=now();


  if(existing&&existing.owner){


    var expired=ts-Number(existing.heartbeatAt||0)>300000;


    if(!expired)throw new Error('已有重任务正在运行');


  }


  var lock={owner:'fifth_season_recall',runId:trim(runId||uid('run')),startedAt:ts,heartbeatAt:ts,expiresAfterMs:300000};


  rawSet(HEAVY_LOCK_KEY,lock,'global');return lock;


}


function heartbeatHeavyLock(runId){var lock=rawGet(HEAVY_LOCK_KEY,'global');if(!lock||lock.owner!=='fifth_season_recall')return;if(runId&&lock.runId!==runId)return;lock.heartbeatAt=now();rawSet(HEAVY_LOCK_KEY,lock,'global')}


function releaseHeavyLock(runId){var lock=rawGet(HEAVY_LOCK_KEY,'global');if(!lock||lock.owner!=='fifth_season_recall')return;if(runId&&lock.runId!==runId)return;rawSet(HEAVY_LOCK_KEY,null,'global')}





async function runRecallScan(opt){


  opt=opt||{};var s=await load();


  if(s.scan.busy){toast('当前已有任务在运行');return null}


  if(s.runtimeTask&&s.runtimeTask.active){toast('已有任务正在执行');return null}


  if(s.scan.cooldownUntil&&now()<s.scan.cooldownUntil&&!opt.force){toast('刚刚发生中断，请稍后再试');return null}





  var currentL=await countAssistant(true);
  var idx=await platformMessageIndexLatest(false);
  if(idx&&idx.floorById)buildMessageMetaIndex(s,null,null,Number(idx.totalMessages||0)||0);
  if(currentL<5){toast('至少聊到 5L 后再扫描');return null}
  var fromL=Math.max(1,Number(opt.fromL||1)||1);


  var toL=Math.max(fromL,Math.min(currentL,Number(opt.toL||currentL)||currentL));


  if(fromL>toL){toast('没有可扫描的内容');return null}


  if(toL-fromL+1<5&&!opt.force){toast('扫描范围至少需要 5L');return null}





  var lock=null;


  try{lock=await acquireHeavyLock(uid('run'))}catch(e){toast(e.message||'无法获取任务锁');return null}





  setScanState(s,'recall_scan',true);


  s.scan.rangeFromL=fromL;s.scan.rangeToL=toL;s.scan.rangeCurrentL=fromL;s.scan.lastSafeL=Math.max(0,fromL-1);


  setTaskState(s,'recall_scan',{label:'事件扫描',rangeText:fromL+'L - '+toL+'L',currentText:'正在预处理',allowPause:true,allowCancel:true});


  addLogToState(s,'事件扫描开始','running',fromL+'L - '+toL+'L',null,{step:'scan_start'});


  await save(s);renderAll(true);





  var windows=buildWindows(fromL,toL,s.settings);
  var windowSize=Math.max(6,Number(s.settings.scanWindowSize||30)||30);
  var totalEvents=0;var totalMoments=0;var totalDetails=0;var pendingSeen={};



  try{


    for(var w=0;w<windows.length;w++){


      s=await load();await refreshScanState(s);


      if(s.scan.cancelRequested){


        setScanState(s,null,false);s.scan.cooldownUntil=now()+60000;


        finishTaskState(s,false,'扫描已取消');


        resolveRunningLog(s,'事件扫描开始',fromL+'L - '+toL+'L','事件扫描已取消','ok','');


        addLogToState(s,'扫描已取消','ok','用户取消');


        await save(s);toast('扫描已取消');renderAll(true);releaseHeavyLock(lock.runId);return null;


      }


      if(s.scan.paused||s.scan.userPauseRequested){


        s.scan.busy=false;s.scan.paused=true;


        updateTaskState(s,{active:true,finished:false,currentText:'扫描已暂停'});


        resolveRunningLog(s,'事件扫描开始',fromL+'L - '+toL+'L','事件扫描已暂停','ok','');


        addLogToState(s,'扫描已暂停','ok','用户暂停');


        await save(s);toast('扫描已暂停');renderAll(true);releaseHeavyLock(lock.runId);return null;


      }





      var win=windows[w];


      s.scan.rangeCurrentL=win.fromL;s.scan.lastAttemptFromL=win.fromL;s.scan.lastAttemptToL=win.toL;s.scan.lastActiveAt=now();


      updateTaskState(s,{currentText:'窗口 '+win.fromL+'L - '+win.toL+'L（'+(w+1)+'/'+windows.length+'）'});


      await save(s);





      try{

        var bundle=await collectRange(win.fromL,win.toL);

        if(!bundle.messages.length)throw makeError('message_collect_empty','这个楼层范围里没有读到可整理的聊天内容。',win.fromL+'L - '+win.toL+'L 没有可整理消息');

        if(bundle.truncated){addLogToState(s,'原文过长已截断','ok',win.fromL+'L - '+win.toL+'L');await save(s)}




        var prompt=await buildExtractPrompt(bundle,s);


        s.scan.lastActiveAt=now();await save(s);


        var rawText=await generateTextRetry(prompt,{max_tokens:2800,temperature:0.12,retries:2,abortKey:'_scanAbort'},s,'事件提取');


        var result=parseExtractResult(rawText,win.fromL,win.toL,bundle,s);





        var acceptedEvents=[];


        for(var ei=0;ei<result.events.length;ei++){


          var ev=result.events[ei];


          if(!acceptEventByOverlapPolicy(s,ev))continue;
          ev.form=avoidRecentForm(ev.form,s,acceptedEvents,ev);


          ev.formContent=normalizeFormContent(ev.form,{},ev);


          ev.formStatus='pending';


          ev.seriesIndex=active(s.events).filter(function(x){return x.form===ev.form}).length+acceptedEvents.filter(function(x){return x.form===ev.form}).length+1;


          updateTaskState(s,{currentText:'生成 '+(FORM_LABELS[ev.form]||ev.form)+' · '+clip(ev.title,18)+'（'+(ei+1)+'/'+result.events.length+'）'});


          s.scan.lastActiveAt=now();await save(s);


          try{


            ev.formContent=await generateEventFormContent(ev,bundle,s);


            ev.formStatus='ok';ev.formError='';ev.formGeneratedAt=now();


            addLogToState(s,'呈现形式完成','ok',(FORM_LABELS[ev.form]||ev.form)+' · '+ev.title);


          }catch(formErr){


            ev.formContent=normalizeFormContent(ev.form,ev.formContent,ev);


            ev.formStatus='fallback';ev.formError=userErrorMessage(formErr,'呈现形式生成');


            logErrorToState(s,'呈现形式生成失败',formErr,ev.title+' · 已使用本地兜底',{step:'form_generation',eventId:ev.id});


          }


          s.events.push(normalizeEvent(ev));acceptedEvents.push(ev);totalEvents++;


          await save(s);heartbeatHeavyLock(lock.runId);


        }


        result.moments.forEach(function(mo){
          var dup=active(s.moments).some(function(m){return m.L===mo.L&&sig(m.quote)===sig(mo.quote)});
          if(!dup){s.moments.push(mo);totalMoments++}
        });
        safeArr(result.details).forEach(function(mo){
          var dup=active(s.moments).some(function(m){return m.L===mo.L&&sig(m.quote)===sig(mo.quote)});
          if(!dup){s.moments.push(mo);totalDetails++}
        });
        if(result.pendingStartL&&result.pendingStartL>win.fromL&&result.pendingStartL<win.toL){
          var pendingKey=result.pendingStartL+'-'+win.toL;
          if(!pendingSeen[pendingKey]){
            pendingSeen[pendingKey]=true;
            windows.splice(w+1,0,{fromL:result.pendingStartL,toL:Math.min(toL,result.pendingStartL+windowSize-1)});
          }
        }

        s.scan.lastSafeL=win.toL;
        resolveFailedRangesByCoverage(s,win.fromL,win.toL);
        markDirty(s,'扫描新增事件');
        addLogToState(s,'窗口完成','ok',win.fromL+'L - '+win.toL+'L · 事件 '+result.events.length+' · 星点 '+(result.moments.length+safeArr(result.details).length));
        await save(s);


        heartbeatHeavyLock(lock.runId);





      }catch(winErr){


        if(winErr&&winErr.name==='AbortError'){


          s=await load();await refreshScanState(s);


          if(s.scan.cancelRequested){setScanState(s,null,false);s.scan.cooldownUntil=now()+60000;finishTaskState(s,false,'扫描已取消');await save(s);toast('扫描已取消');renderAll(true);releaseHeavyLock(lock.runId);return null}


          if(s.scan.userPauseRequested){s.scan.busy=false;s.scan.paused=true;updateTaskState(s,{active:true,finished:false,currentText:'扫描已暂停'});await save(s);toast('扫描已暂停');renderAll(true);releaseHeavyLock(lock.runId);return null}


          markRecoverableInterrupt(s,winErr,'scan_window');finishTaskState(s,false,'扫描中断，可稍后继续');


          logErrorToState(s,'扫描窗口中断',winErr,userErrorMessage(winErr),{step:'scan_window'});


          await save(s);toast(s.scan.lastErrorText);renderAll(true);releaseHeavyLock(lock.runId);return null;


        }


        s.failedRanges.push(normalizeFailedRange({startL:win.fromL,endL:win.toL,reason:userErrorMessage(winErr,'窗口扫描')}));


        logErrorToState(s,'窗口扫描失败',winErr,win.fromL+'L - '+win.toL+'L · '+userErrorMessage(winErr),{step:'scan_window'});


        await save(s);


      }


    }





    var linkedMarks=linkMarksInRange(s,fromL,toL);



    s.progress.lastScannedL=Math.max(s.progress.lastScannedL||0,toL);


    if(toL>s.progress.baselineL)s.progress.processedL=Math.max(s.progress.processedL||0,toL);





    var failCount=active(s.failedRanges).filter(function(x){return!x.resolved}).length;


    finishTaskState(s,true,'扫描完成 · 事件 '+totalEvents+' · 星点 '+(totalMoments+totalDetails)+(linkedMarks?' · 印记 '+linkedMarks:'')+(failCount?' · 失败窗口 '+failCount:''));
    setScanState(s,null,false);
    resolveRunningLog(s,'事件扫描开始',fromL+'L - '+toL+'L','事件扫描完成','ok','事件 '+totalEvents+' · 星点 '+(totalMoments+totalDetails));
    await save(s);toast('扫描完成 · 事件 '+totalEvents+' · 星点 '+(totalMoments+totalDetails));
    renderAll(true);releaseHeavyLock(lock.runId);return{events:totalEvents,moments:totalMoments,details:totalDetails,marks:linkedMarks};



  }catch(e){


    s=await load();


    markRecoverableInterrupt(s,e,s.scan.lastStep||'scan');


    finishTaskState(s,false,userErrorMessage(e,'扫描'));


    logErrorToState(s,'事件扫描失败',e,userErrorMessage(e,'扫描'),{step:'scan'});


    await save(s);toast(userErrorMessage(e,'扫描'));renderAll(true);


    releaseHeavyLock(lock.runId);return null;


  }


}





