  var idx=await platformMessageIndexLatest(true);
  var lastMsgId=idx&&idx.lastAssistantId?mid(idx.lastAssistantId):'';


  s.meta.started=true;s.progress.baselineL=cur;s.progress.processedL=cur;s.progress.lastScannedL=0;


  s.messageMeta=normalizeMessageMeta(s.messageMeta);s.messageMeta.startMessageId=lastMsgId;
  if(idx&&idx.floorById)buildMessageMetaIndex(s,null,null,Number(idx.totalMessages||0)||0);


  s.failedRanges=[];setScanState(s,null,false);


  addLogToState(s,'系统启动','ok','锚定楼层：'+cur+'L');markDirty(s,'启动系统');


