function autoScanCheck(){


  if(app._autoChecking)return;app._autoChecking=true;


  Promise.resolve().then(async function(){


    try{


      var s=await load();


      if(!s.meta.started||!s.settings.autoScanEnabled)return;


      if(s.scan.busy||s.scan.paused||s.scan.cancelRequested||s.scan.recoverable)return;


      if(s.scan.cooldownUntil&&now()<s.scan.cooldownUntil)return;


      if(s.runtimeTask&&s.runtimeTask.active)return;


      var cur=await countAssistant(true);


      var windowSize=Math.max(6,Number(s.settings.scanWindowSize||30)||30);


      var overlap=Math.max(0,Number(s.settings.scanOverlap||6)||6);


      var processed=Number(s.progress.processedL||0)||0;


      var baseline=Number(s.progress.baselineL||0)||0;


      var freshFrom=Math.max(1,processed+1);


      if(cur-freshFrom+1<windowSize)return;


      var nextFrom=Math.max(baseline+1,processed-overlap+1);


      var nextTo=Math.min(cur,nextFrom+windowSize-1);


      await runRecallScan({fromL:nextFrom,toL:nextTo});


    }catch(e){console.warn('[第五季果汁 auto scan]',e)}


    finally{app._autoChecking=false}


  });


}





function startAutoScanTimer(){
