}



// === 标记管理 ===



/*


概念边界：


事件 event = 系统提取的一段完整经历，只进事件列表和事件详情。


高光 moment = 系统提取的单个瞬间，只进记忆星河。


收藏 favorite / 批注 note = 用户给消息做的个人印记，只进我的印记，并在提取时提高关注权重。


用户印记本身不是事件，也不是高光。


*/


async function resolveMarkFloor(s,mark){
  if(!mark.messageId)return Number(mark.L||0)||0;
  s.messageMeta=normalizeMessageMeta(s.messageMeta);
  var key=String(mark.messageId||'');var L=Number(s.messageMeta.floorById[key]||0)||0;
  if(!L){
    var idx=await platformMessageIndexLatest(true);
    if(idx&&idx.floorById)buildMessageMetaIndex(s,null,null,Number(idx.totalMessages||0)||0);
    L=Number(s.messageMeta.floorById[key]||0)||0;


  }
  mark.L=L||0;return mark.L;
}
async function messageExcerptById(messageId){


  var id=String(messageId||'');if(!id)return null;


  var pc=platformCore();
  var found=pc&&pc.getMessageById?await pc.getMessageById(id):null;
  if(!found)return null;
  var L=pc&&pc.getFloorByMessageId?Number(pc.getFloorByMessageId(id)||0)||0:0;


  var text=prepareDialogueContent(found.content||'',found.role||'assistant');


  return{messageId:id,L:L,role:found.role||'',text:text};


}


async function saveMark(payload){


  var s=await load();var mark=normalizeMark(payload||{});


  await resolveMarkFloor(s,mark);


  var excerpt=null;try{if(mark.messageId)excerpt=await messageExcerptById(mark.messageId)}catch(_){}


  if(excerpt&&excerpt.L&&!mark.L)mark.L=excerpt.L;


  if(excerpt&&excerpt.text)mark.preview=cleanMarkPreviewText(excerpt.text,excerpt.role||'assistant');


  else if(mark.preview)mark.preview=cleanMarkPreviewText(mark.preview,'assistant');


  var existing=safeArr(s.marks).find(function(mk){return mk&&!mk.deleted&&mid(mk.messageId)===mid(mark.messageId)&&!!mid(mark.messageId)});
  var meaningful=!!(mark.favorite||mark.note||mark.boundary&&mark.boundary!=='none'||mark.type&&mark.type!=='general'||mark.emotionTags.length||mark.linkedEventId||mark.linkedMomentIds.length);
  if(existing){


    if(!meaningful){existing.deleted=true;existing.updatedAt=now()}


    else{


      existing.L=mark.L||existing.L||0;


      existing.messageId=mark.messageId||existing.messageId||'';
      existing.type=mark.type||'general';


      existing.emotionTags=mark.emotionTags;


      existing.boundary=mark.boundary||'none';


      existing.note=mark.note;


      existing.preview=mark.preview||cleanMarkPreviewText(existing.preview||'','assistant')||'';


      existing.linkedEventId=mark.linkedEventId||'';
      existing.linkedTitle=mark.linkedTitle||'';
      existing.linkedMomentIds=mark.linkedMomentIds;
      existing.favorite=!!mark.favorite;
      existing.visibility=mark.visibility||'inject';


      existing.updatedAt=now();


    }


  }else{


    if(!meaningful){toast('还没有选择标记');return null}


    s.marks.push(mark);


  }


  markDirty(s,'用户标记');addLogToState(s,meaningful?'标记已保存':'标记已清空','ok',(mark.L||0)+'L · '+(mark.type||'general'));


  await save(s);


  toast(meaningful?'标记已保存':'标记已清空');renderAll(true);scheduleMessageMetaRefresh(120);return mark;
}

async function addStarToMarks(momentId){
  var s=await load();var id=trim(momentId);if(!id)return null;
  var mo=active(s.moments).find(function(m){return m.id===id});if(!mo){toast('没有找到这颗星');return null}
  var existing=active(s.marks).find(function(mk){return safeArr(mk.linkedMomentIds).indexOf(id)>=0});
  var ev=active(s.events).find(function(e){return (mo.linkedEventId&&e.id===mo.linkedEventId)||Number(mo.L||0)>=Number(e.startL||0)&&Number(mo.L||0)<=Number(e.endL||0)});
  if(existing){
    existing.favorite=true;existing.linkedMomentIds=addUniqueId(existing.linkedMomentIds,id);
    if(ev){existing.linkedEventId=ev.id;existing.linkedTitle=ev.title||existing.linkedTitle||'';ev.sourceMarkIds=addUniqueId(ev.sourceMarkIds,existing.id)}
    mo.sourceMarkIds=addUniqueId(mo.sourceMarkIds,existing.id);existing.processed=true;existing.updatedAt=now();
    markDirty(s,'星点收进印记');await save(s);toast('已收进你的印记');renderAll(true);return existing;
  }
  var mark=normalizeMark({
    L:Number(mo.L||0)||0,type:'star',favorite:true,processed:true,
    preview:mo.quote||mo.scene||mo.title||'星河里的那一刻',
    note:'',linkedEventId:ev&&ev.id||mo.linkedEventId||'',linkedTitle:ev&&ev.title||'',
