async function rerollEventForm(id,newForm){
  var s=await load();
  var ev=active(s.events).find(function(x){return x.id===id});
  if(!ev)return false;
  var previousForm=ev.form;
  var previousFormContent=JSON.parse(JSON.stringify(ev.formContent||{}));
  if(newForm)ev.form=normForm(newForm)||ev.form;


  var bundle=await collectRange(ev.startL,ev.endL);

  if(!bundle||!bundle.messages||!bundle.messages.length){

    toast('找不到原始对话内容，无法重抽');

    return false;

  }



  addLogToState(s,'重抽呈现形式','running',ev.title);

  await save(s);



  try{
    ev.formContent=await generateEventFormContent(ev,bundle,s,{reroll:true,newForm:!!newForm,previousForm:previousForm,previousFormContent:previousFormContent});
    ev.formStatus='ok';

    ev.formError='';

    ev.formGeneratedAt=now();

    ev.updatedAt=now();

    resolveRunningLog(s,'重抽呈现形式',ev.title,'重抽完成','ok',FORM_LABELS[ev.form]||ev.form);

  }catch(e){

    ev.formContent=normalizeFormContent(ev.form,ev.formContent,ev);

