async function fetchApiModels(){

  var s=await load();var cfg=effectiveApiSettings(s);

  if(!cfg.apiBaseUrl||!cfg.apiKey){

    var cfgErr=makeError('api_config_missing','还没有配置可用接口','获取模型列表缺少 apiBaseUrl 或 apiKey');

    logErrorToState(s,'获取模型列表失败',cfgErr,userErrorMessage(cfgErr),{step:'requesting_model'});

    await save(s);toast(userErrorMessage(cfgErr,'获取模型'));renderAll(true);return[]

  }

  var url=cfg.apiBaseUrl.replace(/\/+$/,'');

  if(/\/v1$/i.test(url))url+='/models';else if(/\/v1\/chat\/completions$/i.test(url))url=url.replace(/\/chat\/completions$/i,'/models');else url+='/models';

  addLogToState(s,'获取模型列表','running','',null,{step:'requesting_model'});await save(s);

  try{

    var r=await fetch(url,{method:'GET',headers:{'Content-Type':'application/json','Authorization':'Bearer '+cfg.apiKey}});

    if(!r.ok){var bt='';try{bt=await r.text()}catch(_){}throw apiError(r.status,bt,null)}

    var d;try{d=await r.json()}catch(jsonErr){throw makeError('format_error','模型列表返回格式不对','模型列表响应不是 JSON：'+errDetail(jsonErr))}

    var list=safeArr(d&&d.data).map(function(x){return x&&x.id?String(x.id):''}).filter(Boolean).sort();

    if(!list.length)throw makeError('empty_response','接口未返回可用模型','models 接口 data 为空');

    saveGlobalConfig({activeApiProfileId:cfg.activeApiProfileId,models:list});
    resolveRunningLog(s,'获取模型列表','','获取模型列表成功','ok','共 '+list.length+' 个');await save(s);return list;
  }catch(e){resolveRunningLog(s,'获取模型列表','','获取模型列表失败','err',userErrorMessage(e),e);await save(s);toast(userErrorMessage(e,'获取模型'));renderAll(true);return[]}

}




