function splitParagraphs(text){
  text=trim(String(text==null?'':text).replace(/\r\n/g,'\n').replace(/\r/g,'\n'));
  if(!text)return[];
  var out=[];
  text.split(/\n+/).map(trim).filter(Boolean).forEach(function(block){
    block=block.replace(/[ \t]+/g,' ');
    if(block.length<=170){out.push(block);return}
    var parts=block.split(/([。！？!?；;])/),buf='';
    for(var i=0;i<parts.length;i+=2){
      var one=trim((parts[i]||'')+(parts[i+1]||''));
