      if(buf&&buf.length+one.length>170){out.push(buf);buf=''}
      buf+=one;
      if(buf.length>=110){out.push(buf);buf=''}
    }
    if(buf)out.push(buf);
    if(!out.length||out[out.length-1]===block){
      while(block.length>170){out.push(block.slice(0,170));block=block.slice(170)}
      if(block)out.push(block);
    }
  });
  return out;
}

