function importanceLabel(v){v=Math.max(1,Math.min(5,Math.round(Number(v)||3)));return IMPORTANCE_LABELS[v]||('等级 '+v)}
function tagLine(ev){var arr=[];if(ev.tag)arr.push(ev.tag);if(ev.mood)arr.push(ev.mood);if(ev.era)arr.push(ev.era);if(ev.importance)arr.push(importanceLabel(ev.importance));return arr}

function eventsSorted(s){return active(s.events).sort(function(a,b){return(Number(b.endL||0)||0)-(Number(a.endL||0)||0)})}
function eventById(s,id){return active(s.events).filter(function(x){return x.id===id})[0]||null}
function markFloor(s,m){var L=0;if(m&&m.messageId&&s&&s.messageMeta&&s.messageMeta.floorById)L=Number(s.messageMeta.floorById[String(m.messageId)]||0)||0;if(!L)L=Number(m&&m.L||0)||0;return L}
function eventForFloor(s,L){L=Number(L||0)||0;if(!L)return null;return eventsSorted(s).filter(function(ev){return L>=Number(ev.startL||0)&&L<=Number(ev.endL||0)})[0]||null}
function floorSearchState(s,key){s=s||{};s.ui=s.ui||{};var L=Math.max(0,Number(s.ui['floorSearchL_'+key]||0)||0);return{L:L,open:!!s.ui['floorSearchOpen_'+key]||!!L}}
function floorMatchesRange(item,L){L=Number(L||0)||0;if(!L)return true;var start=Number(item&&item.startL||item&&item.L||0)||0;var end=Number(item&&item.endL||item&&item.L||start)||start;return start>0&&L>=start&&L<=end}
function floorSearchHtml(s,key,total,hit){
