function statusText(s){

  if(!s||!s.meta||!s.meta.started)return'未启动';

  if(s.scan&&s.scan.busy)return'扫描中';

  if(s.scan&&s.scan.paused)return'已暂停';

  if(s.scan&&s.scan.recoverable)return'可继续';

  if(s.settings&&!s.settings.autoScanEnabled)return'手动就绪';

  return'运行中';

}



function unreadLogsCount(s){var readAt=Number(s.uiUnread&&s.uiUnread.logsReadAt||0)||0;return safeArr(s.logs).filter(function(x){return Number(x.time||0)>readAt}).length}

function routeSnapshot(s){s=s||{};var ui=s.ui||{};return{page:ui.page||'home',currentEventId:ui.currentEventId||'',currentMomentId:ui.currentMomentId||'',currentGalaxyEventId:ui.currentGalaxyEventId||'',highlightStarId:ui.highlightStarId||'',formFilter:ui.formFilter||'all',eventTab:ui.eventTab||'time',markTab:ui.markTab||'all'}}

function applyRoute(s,r){s.ui=s.ui||{};r=r||{page:'home'};s.ui.page=r.page||'home';s.ui.currentEventId=r.currentEventId||'';s.ui.currentMomentId=r.currentMomentId||'';s.ui.currentGalaxyEventId=r.currentGalaxyEventId||'';s.ui.highlightStarId=r.highlightStarId||'';s.ui.formFilter=r.formFilter||s.ui.formFilter||'all';s.ui.eventTab=r.eventTab||s.ui.eventTab||'time';s.ui.markTab=r.markTab||s.ui.markTab||'all'}

function goPage(s,page,patch){s.ui=s.ui||{};s.ui.routeStack=safeArr(s.ui.routeStack);var cur=routeSnapshot(s);if(cur.page!==page)s.ui.routeStack.push(cur);if(s.ui.routeStack.length>20)s.ui.routeStack=s.ui.routeStack.slice(-20);s.ui.page=page||'home';Object.assign(s.ui,patch||{})}

function backPage(s){s.ui=s.ui||{};s.ui.routeStack=safeArr(s.ui.routeStack);var prev=s.ui.routeStack.pop();if(prev)applyRoute(s,prev);else{s.ui.page='home';s.ui.currentEventId='';s.ui.currentMomentId='';s.ui.currentGalaxyEventId='';s.ui.highlightStarId=''}}



function eventCard(ev){

