  return"<div class='tr3-ev-card' data-act='open-event' data-id='"+esc(ev.id)+"'><div class='tr3-ev-top'><div><div class='tr3-range'>"+esc(ev.startL+'L - '+ev.endL+'L')+"</div><div class='tr3-ev-title'>"+esc(ev.title||'未命名事件')+"</div><div class='tr3-ev-time'>"+esc(ev.timeLabel||ev.time_label||'')+"</div></div><div class='tr3-form-ico'>"+formIcon(ev.form)+"</div></div>"+

    "<div class='tr3-ev-q'>"+esc(clip(ev.summary||'',96))+"</div><div class='tr3-chip-row'><span class='tr3-chip hot'>"+esc(formLabel(ev.form))+"</span>"+tags+(ev.favorite?"<span class='tr3-chip hot'>收藏</span>":"")+(ev.userNote?"<span class='tr3-chip hot'>批注</span>":"")+"</div></div>";

