function eventsHtml(s){
  var events=eventsSorted(s);var tab=(s.ui&&s.ui.eventTab)||'time';
  function tabBtn(k,t){return"<button class='tr3-event-tab "+(tab===k?'on':'')+"' data-event-tab='"+k+"'>"+t+"</button>"}
  var body='',search='';
  if(tab==='forms'){
    var desc={counseling:'一册连续的咨询记录',court:'一卷一卷内心判决',letter:'一沓没有寄出的信',newspaper:'一叠旧报纸剪报'};
    body=RECALL_FORMS.map(function(f){var list=events.filter(function(ev){return ev.form===f});return"<div class='tr3-series-card' data-act='open-series' data-form='"+f+"'><div class='tr3-series-ico'>"+formIcon(f)+"</div><div><div class='tr3-series-title'>"+esc(formLabel(f))+" · "+list.length+"</div><div class='tr3-series-desc'>"+esc(desc[f])+(list[0]?"<br>最新："+esc(clip(list[0].title,28)):"")+"</div></div></div>"}).join('');
  }else{
    var st=floorSearchState(s,'events');var list=st.L?events.filter(function(ev){return floorMatchesRange(ev,st.L)}):events;
    search=floorSearchHtml(s,'events',events.length,list.length);
    body=list.length?list.map(eventCard).join(''):"<div class='tr3-empty'><div class='tr3-empty-icon'>📕</div>"+(st.L?("没有找到覆盖 "+esc(st.L)+"L 的事件。"):"还没有提取到事件。<br>先去任务中心手动扫描，或者继续聊天后再回来扫描。")+"</div>";
  }
  return"<div class='tr3-page'><div class='tr3-head'><div class='tr3-head-bar'><div class='tr3-head-left'><button class='tr3-back-btn' data-act='back'>←</button><span class='tr3-head-title'>事件回忆</span></div><button class='tr3-back-btn' data-base-close='1'>×</button></div></div><div class='tr3-event-tabs'>"+tabBtn('time','按时间')+tabBtn('forms','按形式')+"</div><div class='tr3-main'>"+search+body+"</div></div>";
}

function seriesHtml(s){
