async function openMarkItem(id){

  var s=await core().load();var mark=active(s.marks).filter(function(m){return m.id===id})[0]||null;

  if(!mark){base().toast&&base().toast('这条印记找不到了');return}

  var L=markFloor(s,mark);var ev=eventForFloor(s,L);

  if(ev){goPage(s,'event',{currentEventId:ev.id});await core().save(s);return renderAll(true)}

  var info=null;try{if(core().messageExcerptById)info=await core().messageExcerptById(mark.messageId)}catch(_){}

  var raw=trim(info&&info.text||mark.preview||mark.note||'这条消息暂时没有取到原文。');

  var cleaner=core().cleanMarkPreviewText;

  var text=trim(cleaner?cleaner(raw,'assistant'):raw);

  var title=(L?L+'L · ':'')+(mark.favorite?'收藏':'印记');

  var body="<div class='tr3-sec-card'>"+br(text)+"</div>"+(mark.note?"<div class='tr3-sec-card'><div style='font-size:10px;font-weight:950;color:#EC4899;margin-bottom:6px'>我的批注</div>"+br(mark.note)+"</div>":"");

  base().openOverlay&&base().openOverlay(title,'还没有归入事件，先显示消息原文',body);

}



