function apiError(status,bodyText,bodyObj){
  var msg='';
  try{
    if(bodyObj){
      msg=apiPartText(bodyObj.error&&bodyObj.error.message)||apiPartText(bodyObj.message)||apiPartText(bodyObj.error)||apiPartText(bodyObj);
    }
  }catch(_e){}
  if(!msg)msg=String(bodyText||'');
  var err=new Error('HTTP '+status+' '+clip(msg,500));
  err.httpStatus=status;
  err.responseBody=bodyText||'';
  err.responseJson=bodyObj||null;
  err.devDetail='HTTP '+status+' '+(bodyText||msg||'');
  return err;
}
function classifyError(e){
  var direct=String(e&&e.code||'');

  if(/^(api_timeout|rate_limit|server_error|network_error|empty_response|format_error|api_config_missing)$/.test(direct))return direct;

  var raw=[
    String(e&&e.message||e||''),
    String(e&&e.devDetail||''),
    String(e&&e.responseBody||'')
  ].join('\n');
  var low=raw.toLowerCase();
  var status=Number(e&&e.httpStatus||0)||0;

  if(e&&e.name==='AbortError')return 'abort';
  if(/prohibited_content|prohibited content|blocked by.*safety|safety policy|安全策略|审核拦截/.test(low))return 'prohibited_content';
  if(/safety|safety_blocked|blocked reason|harm category/.test(low))return 'safety_blocked';
  if(/billing|billable|enable billing|计费/.test(low))return 'billing_required';
  if(status===401||/invalid api key|api key invalid|unauthorized|invalid_api_key|authentication/.test(low))return 'auth_invalid';
  if(status===403||/permission denied|forbidden|not allowed|无权限|没有权限/.test(low))return 'permission_denied';
  if(status===404||/model not found|not found|模型不存在|no such model/.test(low))return 'model_not_found';
  if(/endpoint|base url|invalid url|unsupported url|接口地址/.test(low))return 'endpoint_invalid';
  if(status===413||/request too large|payload too large|body too large|请求过大/.test(low))return 'request_too_large';
  if(/context too long|maximum context|token limit|too many tokens|上下文.*长|内容过长/.test(low))return 'context_too_long';
  if(status===429||/rate limit|too many requests/.test(low))return 'rate_limit';
  if(/quota|insufficient|balance|余额|额度/.test(low))return 'quota';
  if(status>=500||/servererror|server error|\b500\b|\b502\b|\b503\b|\b504\b|api 返回 5/.test(low))return 'server_error';
  if(/timeout|timed out|超时|lorebook_update timeout|callparentwithresult/.test(low))return 'api_timeout';
  if(/fetch|network|failed to fetch|networkerror|网络/.test(low))return 'network_error';
  if(/没有正文|empty|no content|返回为空|无可用端点|模型没有返回可用内容|接口未返回可用模型|未返回可用内容/.test(low))return 'empty_response';
  if(/无效阶段总结|无效长期记忆|无效历史总览|格式/.test(low))return 'format_error';
  if(/未配置 api|api key|base url/.test(low))return 'api_config_missing';
  return 'unknown_error';
}

// 把校验细分原因码翻译成用户能看懂的提示，不再糊成一句“格式不符合记忆要求”
function describeParseCode(code){
  code=trim(code||'');
  if(code==='too_short')return '模型返回内容过短，可能这段楼层信息太少，建议再聊一阵后重试。';
  if(code==='placeholder')return '模型返回了空内容或占位文字，可能是接口异常或额度不足。';
  if(code==='looks_like_error')return '模型返回的内容像是接口报错信息（含 rate limit / error / timeout 等英文错误词），可能上游接口异常。';
  if(code==='missing_sections')return '模型未按【时间锚点】【关键事件】等规定章节格式总结，建议重试或换一个总结模型。';
  return '模型返回格式不符合记忆要求，请稍后重试。';
}

function userErrorMessage(e,context){
  var code=classifyError(e);

  if(code==='prohibited_content')return '当前整理请求被模型安全策略拦截，可能与聊天内容中的敏感桥段有关。建议缩小整理范围，或更换总结模型。';
  if(code==='safety_blocked')return '当前请求被模型安全规则拦截。建议缩小楼层范围，或更换审核更宽松的总结模型。';
  if(code==='billing_required')return '当前接口未开通计费权限，暂时无法调用这个模型或方法。';
  if(code==='auth_invalid')return '密钥不对，请检查设置里的接口配置。';
  if(code==='permission_denied')return '当前接口没有调用权限，请检查模型权限或中转站配置。';
  if(code==='model_not_found')return '当前模型不存在，或接口地址配置不正确。';
  if(code==='endpoint_invalid')return '接口地址可能不对，请检查设置里的接口地址。';
  if(code==='request_too_large')return '本次请求内容过大，请缩小楼层范围后重试。';
  if(code==='context_too_long')return '本次整理内容过长，请缩小楼层范围后重试。';
  if(code==='rate_limit')return '当前请求过快，接口暂时限流，请稍后再试。';
  if(code==='quota')return '接口额度不足，请检查当前站点余额或额度。';
  if(code==='server_error')return '上游服务异常，请稍后再试。';
  if(code==='abort')return '请求被中断，可能与锁屏、切后台或网络切换有关。';
  if(code==='api_timeout')return '接口响应超时，请保持前台并稍后重试。';
  if(code==='network_error')return '网络连接异常，请检查网络状态。';
  if(code==='empty_response')return '模型没有返回可用内容。';
  if(code==='format_error')return describeParseCode(e&&e.parseCode)||'模型返回格式不符合记忆要求，请稍后重试。';
  if(code==='api_config_missing')return '还没有可用的接口配置，请先去设置里保存。';

  var raw=String(
    e&&e.message ||
    e&&e.devDetail ||
    e&&e.responseBody ||
    ''
  ).trim();

  raw=raw.replace(/^HTTP\s*\d+\s*/i,'').replace(/^Error:\s*/i,'').trim();

  if(/模型没有返回可用内容/.test(raw))return '模型没有返回可用内容。';
  if(/接口未返回可用模型/.test(raw))return '接口未返回可用模型。';

  if(/[\u4e00-\u9fff]/.test(raw) && raw.length<=60 && raw.indexOf('{')<0 && raw.indexOf('stack')<0){
    return raw.replace(/。?$/,'。');
  }

  return (context?context+'失败：':'任务执行失败：')+'请稍后重试。';
}

