    if(!it||it.status!=='running')continue;

    var textOk=!matchText||String(it.text||'')===String(matchText||'');
    var detailOk=!matchDetail||String(it.detail||'')===String(matchDetail||'');

    if(textOk&&detailOk){
      it.text=String(nextText||it.text||'');
      it.status=nextStatus||'ok';
      it.detail=String(nextDetail==null?it.detail:nextDetail);
      if(error){
        it.stack=error&&error.stack?String(error.stack):'';
        it.code=it.code||classifyError(error);
        it.devDetail=it.devDetail||String(error&&error.devDetail||error&&error.responseBody||error&&error.message||error||'');
      }
      return true;
    }
  }
  return false;
}

