async function listImportWorldbooks(){
  var out=[],seen={};
  if(!T.tavo||!T.tavo.lorebook||!T.tavo.lorebook.all)return out;
  var all=[];
  try{all=await hostCall(function(){return T.tavo.lorebook.all()},'lorebook.all.import-list',12000,{silent:true,fallback:[]})}catch(_){all=[]}
  safeArr(all).forEach(function(book,i){
    var id=trim(book&&book.id);
    if(!id||seen[id])return;
    seen[id]=true;
    var entries=safeArr(book&&book.entries);
    out.push({
      id:id,
      name:trim(book&&book.name||('世界书 '+(i+1))),
      entryCount:entries.length,
      selected:false
    });
  });
  out.sort(function(a,b){return String(a.name||'').localeCompare(String(b.name||''),'zh-Hans-CN')});
  return out.slice(0,120);
}
