async function loadPreludeSourceEntry(bookId){
  if(!T.tavo||!T.tavo.lorebook||!T.tavo.lorebook.get)throw new Error('当前宿主不支持读取世界书');
  bookId=trim(bookId);
  if(!bookId)throw new Error('请先选择一本世界书');
  var book=null;
  try{
    book=await hostCall(function(){return T.tavo.lorebook.get(bookId)},'lorebook.get.prelude-source',12000,{silent:true,fallback:null});
  }catch(e){
    throw new Error(userErrorMessage(e,'读取世界书'));
  }
  if(!book)throw new Error('没有读取到选中的世界书');
  var entries=safeArr(book.entries);
  if(entries.length!==1)throw new Error('选中的世界书必须只有 1 个条目，当前是 '+entries.length+' 个');
  var src=preludeSourceFromWorldbookEntry(book,entries[0],0);
  if(!src)throw new Error('选中条目内容为空');
  return src;
}
