async function save(s,opt){
  opt=opt||{};
  s=normalize(s||app.state||{});
  var chatId=s.chatId||await currentChatId({required:true});
  if(!chatId||chatId==='default')chatId=await currentChatId({required:true});
  s.chatId=chatId;
  s.meta.updatedAt=now();
  s.meta.lastSaveAt=now();
  s.meta.saveSeq=(Number(s.meta.saveSeq||0)||0)+1;
  s.meta.rev=(Number(s.meta.rev||0)||0)+1;
  s.sync.localSaved=true;
  app.state=s;
  await rawSet(getStoreKey(chatId),s,'chat');
  if(opt.verify){
    var rb=normalize(rawGet(getStoreKey(chatId),'chat')||{});
    if(Number(rb.meta&&rb.meta.saveSeq||0)!==Number(s.meta.saveSeq||0))throw new Error('保存校验失败');
  }
  return s;
}

function memoDataStats(x){
  x=x&&typeof x==='object'?x:{};
  var summaries=safeArr(x.summaries).filter(function(v){return v&&!v.deleted});
  var longTerms=safeArr(x.longTerms).filter(function(v){return v&&!v.deleted});
  var hov=x.historyOverview&&!x.historyOverview.deleted?1:0;
  var baseline=Number(x.progress&&x.progress.baselineL||x.baselineL||0)||0;
  var processed=Number(x.progress&&x.progress.processedL||x.processedL||0)||0;
  var backfill=Number(x.progress&&x.progress.backfillProcessedL||x.backfillProcessedL||0)||0;
  var injectId=trim(x.sync&&x.sync.injectBookId||x.lorebook_meta&&x.lorebook_meta.inject_id||'');
  var count=summaries.length+longTerms.length+hov;
  return{summaryCount:summaries.length,longTermCount:longTerms.length,historyOverviewCount:hov,baselineL:baseline,processedL:processed,backfillProcessedL:backfill,injectBookId:injectId,count:count,meaningful:count>0||processed>0||backfill>0||!!injectId};
}

function looksOldMemoData(x){
  x=x&&typeof x==='object'?x:null;
  if(!x)return false;
  var st=memoDataStats(x);
  if(!st.meaningful)return false;
  if(x.lorebook_meta||x.baselineL!=null||x.processedL!=null||x.backfillProcessedL!=null)return true;
  if(!x.meta||!Number(x.meta.rev||0))return true;
  if(x.schemaVersion&&x.schemaVersion!==VER)return true;
  return false;
}

async function memoRawCandidates(chatId){
  chatId=chatId||await currentChatId();
  var keys=[getStoreKey(chatId),getStoreKey('default'),STORE];
  var out=[],seen={};
  keys.forEach(function(k){
    if(!k||seen[k])return;
    seen[k]=1;
    var raw=rawGet(k,'chat');
    if(raw&&typeof raw==='object')out.push({key:k,raw:raw,stats:memoDataStats(raw),old:looksOldMemoData(raw)});
  });
  return out;
}

async function tav088UpgradeStatus(s){
  s=s||app.state||await load();
  var chatId=s.chatId||await currentChatId();
  var candidates=await memoRawCandidates(chatId);
  var best=null;
  candidates.forEach(function(c){
    if(!c.stats||!c.stats.meaningful)return;
    if(!best||c.stats.count>best.stats.count||c.old&&!best.old)best=c;
  });
  var cur=memoDataStats(s);
  var available=!!(best&&best.stats&&best.stats.meaningful)||cur.meaningful;
  return{
    available:available&&!s.meta.tav088ChoiceMade&&!s.meta.tav088NoticeDismissed,
    hasOld:!!(best&&best.old),
    sourceKey:best&&best.key||'',
    summaryCount:(best&&best.stats.summaryCount)||cur.summaryCount,
    longTermCount:(best&&best.stats.longTermCount)||cur.longTermCount,
    historyOverviewCount:(best&&best.stats.historyOverviewCount)||cur.historyOverviewCount,
    baselineL:(best&&best.stats.baselineL)||cur.baselineL,
    processedL:(best&&best.stats.processedL)||cur.processedL,
    injectBookId:(best&&best.stats.injectBookId)||cur.injectBookId
  };
}

