async function migrateOldMemoToTav088(){
  var chatId=await currentChatId({required:true});
  var candidates=await memoRawCandidates(chatId);
  var best=null;
  candidates.forEach(function(c){
    if(!c.stats||!c.stats.meaningful)return;
    if(!best||c.old&&!best.old||c.stats.count>best.stats.count)best=c;
  });
  if(!best){
    toast('没有检测到可迁移的旧记忆数据');
    return null;
  }
  var backupKey=await backupMemoRaw(best.raw,chatId,'oldmemo');
  var s=normalize(best.raw);
  s.chatId=chatId;
  s.meta.started=!!(s.meta.started||memoDataStats(s).meaningful);
  s.meta.tav088ChoiceMade=true;
  s.meta.tav088Choice='迁移旧数据';
  s.meta.tav088ChoiceAt=now();
  s.meta.tav088BackupKey=backupKey;
  s.meta.tav088NoticeDismissed=true;
  s.sync=s.sync||{};
  s.sync.injectBookId=s.sync.injectBookId||best.stats.injectBookId||null;
  addLogToState(s,'旧数据迁移完成','ok','已转换为新格式，旧数据已保留副本');
  await save(s,{verify:true});
  if(memoDataStats(s).count>0){
    try{await syncInjectBook(s,'tav088-migrate-old')}catch(syncErr){markSyncError(s,syncErr&&syncErr.message||'同步失败');await save(s)}
  }
  try{await setMemoInjectBinding(true,s)}catch(_bind){}
  toast('旧数据已迁移');
  renderAll(true);
  return s;
}

