function activeSummariesSorted(s){
  return safeArr(s&&s.summaries).filter(function(x){
    return x&&!x.deleted&&Number(x.startL||0)>0&&Number(x.endL||0)>=Number(x.startL||0);
  }).slice().sort(function(a,b){
    var ae=Number(a.endL||0)||0,be=Number(b.endL||0)||0;
    if(ae!==be)return ae-be;
    return (Number(a.startL||0)||0)-(Number(b.startL||0)||0);
  });
}

function activeLongTermsSorted(s){
  return safeArr(s&&s.longTerms).filter(function(x){
    return x&&!x.deleted&&x.windowEligible!==false&&Number(x.startL||0)>0&&Number(x.endL||0)>=Number(x.startL||0);
  }).slice().sort(function(a,b){
    var ae=Number(a.endL||0)||0,be=Number(b.endL||0)||0;
    if(ae!==be)return ae-be;
    return (Number(a.startL||0)||0)-(Number(b.startL||0)||0);
  });
}

function getCoverageMap(fromL,toL){
  var s=normalize(app.state||{});
  fromL=Math.max(1,Number(fromL||1)||1);
  toL=Math.max(fromL,Number(toL||fromL)||fromL);
  function hit(x){var a=Number(x.startL||0)||0,b=Number(x.endL||0)||0;return a&&b&&a<=toL&&b>=fromL}
  function row(x,type){return{id:trim(x.id||''),type:type,startL:Number(x.startL||0)||0,endL:Number(x.endL||0)||0,startMessageId:mid(x.startMessageId||''),endMessageId:mid(x.endMessageId||''),title:clip(trim(x.title||''),48),stale:!!x.stale}}
  var summaries=activeSummariesSorted(s).filter(hit).map(function(x){return row(x,'summary')}).slice(0,20);
  var longTerms=activeLongTermsSorted(s).filter(hit).map(function(x){return row(x,'long')}).slice(0,12);
  var overview=s.historyOverview&&hit(s.historyOverview)?row(s.historyOverview,'overview'):null;
  return{version:'1.0',fromL:fromL,toL:toL,hasCoverage:!!(summaries.length||longTerms.length||overview),summaries:summaries,longTerms:longTerms,historyOverview:overview};
}

function activeInjectableLongTermsSorted(s){
  return activeLongTermsSorted(s).filter(function(x){return !x.stale});
}

function hasExactSummaryRange(s,startL,endL){
  startL=Number(startL||0)||0;
  endL=Number(endL||0)||0;
  return activeSummariesSorted(s).some(function(x){
    return Number(x.startL||0)===startL&&Number(x.endL||0)===endL;
  });
}

function hasExactLongTermRange(s,startL,endL){
  startL=Number(startL||0)||0;
  endL=Number(endL||0)||0;
  return activeLongTermsSorted(s).some(function(x){
    return Number(x.startL||0)===startL&&Number(x.endL||0)===endL;
  });
}

function findContinuousCoveredEnd(items,startL){
  startL=Math.max(1,Number(startL||1)||1);
  var covered=startL-1;
  items=safeArr(items).slice().sort(function(a,b){
    var as=Number(a.startL||0)||0,bs=Number(b.startL||0)||0;
    if(as!==bs)return as-bs;
    return (Number(a.endL||0)||0)-(Number(b.endL||0)||0);
  });
  for(var i=0;i<items.length;i++){
    var st=Number(items[i].startL||0)||0;
    var ed=Number(items[i].endL||0)||0;
    if(ed<=covered)continue;
    if(st<=covered+1){
      covered=Math.max(covered,ed);
    }else{
      break;
    }
  }
  return covered;
}

function subtractRanges(fromL,toL,list){
  fromL=Math.max(1,Number(fromL||1)||1);
  toL=Math.max(fromL,Number(toL||fromL)||fromL);
  list=safeArr(list).slice().sort(function(a,b){
    return (Number(a.startL||0)||0)-(Number(b.startL||0)||0);
  });
  var cur=fromL;
  var out=[];
  for(var i=0;i<list.length;i++){
    var st=Number(list[i].startL||0)||0;
    var ed=Number(list[i].endL||0)||0;
    if(ed<cur)continue;
    if(st>toL)break;
    if(st>cur)out.push({startL:cur,endL:Math.min(toL,st-1)});
    cur=Math.max(cur,ed+1);
    if(cur>toL)break;
  }
  if(cur<=toL)out.push({startL:cur,endL:toL});
  return out.filter(function(x){return x.startL<=x.endL});
}
function buildStandardSegments(fromL,toL,interval){
  fromL=Math.max(1,Number(fromL||1)||1);
  toL=Math.max(fromL,Number(toL||fromL)||fromL);
  interval=Math.max(1,Number(interval||1)||1);

  var out=[];
  var cur=fromL;
  while(cur<=toL){
    var end=Math.min(cur+interval-1,toL);
    out.push({startL:cur,endL:end});
    cur=end+1;
  }
  return out;
}

function getMissingSegmentsInRange(s,fromL,toL,interval){
  var covered=activeSummariesSorted(s).map(function(x){return{startL:Number(x.startL||0)||0,endL:Number(x.endL||0)||0}});
  var gaps=subtractRanges(fromL,toL,covered);
  var out=[];
  gaps.forEach(function(g){out=out.concat(buildStandardSegments(g.startL,g.endL,interval))});
  return out;
}


function normalizeSummaryRangesForLongTerm(s){
  return activeSummariesSorted(s).slice().sort(function(a,b){
    var as=Number(a.startL||0)||0, bs=Number(b.startL||0)||0;
    if(as!==bs)return as-bs;
    return (Number(a.endL||0)||0)-(Number(b.endL||0)||0);
  });
}

function updateProgressFromSummaries(s){
  var baseline=Math.max(0,Number(s.progress&&s.progress.baselineL||0)||0);
  var sums=activeSummariesSorted(s);
  var history=sums.filter(function(x){return Number(x.endL||0)<=baseline});
  var live=sums.filter(function(x){return Number(x.endL||0)>baseline});
  var historyEnd=findContinuousCoveredEnd(history,1);
  var liveEnd=findContinuousCoveredEnd(live,Math.max(1,baseline+1));
  s.progress.backfillProcessedL=Math.max(0,historyEnd);
  s.progress.processedL=Math.max(baseline,liveEnd<baseline+1?baseline:liveEnd);
}

function detectUnrecordedRanges(s,currentAssistantCount){
  currentAssistantCount=Math.max(0,Number(currentAssistantCount||0)||0);
  var covered=[];
  if(Number(s.progress.backfillProcessedL||0)>0){
    covered.push({startL:1,endL:Number(s.progress.backfillProcessedL||0)||0});
  }
  if(Number(s.progress.processedL||0)>Number(s.progress.baselineL||0)){
    covered.push({startL:Math.max(1,(Number(s.progress.baselineL||0)||0)+1),endL:Number(s.progress.processedL||0)||0});
  }
  var out=[];
  if(currentAssistantCount>0){
    out=subtractRanges(1,currentAssistantCount,covered);
  }
  s.progress.unrecordedRanges=out;
}
function resolveFailedRangesByCoverage(s,startL,endL){
  startL=Math.max(1,Number(startL||1)||1);
  endL=Math.max(startL,Number(endL||startL)||startL);

  s.failedRanges=safeArr(s.failedRanges).map(function(x){
    if(!x||x.resolved)return x;
    var fs=Number(x.startL||0)||0;
    var fe=Number(x.endL||0)||0;

    // 完全覆盖
    if(startL<=fs && endL>=fe){
      x.resolved=true;
      return x;
    }

    return x;
  });
}


function buildInjectPlan(s){
  var longCount=Math.max(1,Number(s.settings.injectLongCount||2)||2);
  var shortCount=Math.max(1,Number(s.settings.injectShortCount||3)||3);
  var allLongs=activeInjectableLongTermsSorted(s);
  var injectLongs=allLongs.slice(-longCount);

  var coveredByLongIds={};
  injectLongs.forEach(function(lt){
    safeArr(lt.sourceSummaryIds).forEach(function(id){coveredByLongIds[id]=true});
  });

  var allShorts=activeSummariesSorted(s);
  var recentShorts=allShorts.slice(-shortCount);
  var injectShorts=recentShorts.filter(function(sum){
    return !coveredByLongIds[sum.id];
  });

  var items=[];
  injectLongs.forEach(function(x){items.push({type:'long',item:x})});
  injectShorts.forEach(function(x){items.push({type:'short',item:x})});

  var earliestStart=0;
  items.forEach(function(x){
    var st=Number(x.item&&x.item.startL||0)||0;
    if(!st)return;
    earliestStart=!earliestStart?st:Math.min(earliestStart,st);
  });

  var desiredHistoryEnd=0;
  if(earliestStart>1){
    desiredHistoryEnd=earliestStart-1;
  }

  var historyContinuousEnd=findContinuousCoveredEnd(
    allShorts.filter(function(x){return Number(x.endL||0)<=desiredHistoryEnd}),
    1
  );
  if(historyContinuousEnd<desiredHistoryEnd)desiredHistoryEnd=historyContinuousEnd;
  if(desiredHistoryEnd<1)desiredHistoryEnd=0;

  return {
    injectLongs:injectLongs,
    injectShorts:injectShorts,
    earliestStart:earliestStart,
    desiredHistoryEnd:desiredHistoryEnd
  };
}

function markDependentLongTermsStale(s,summaryIds,reason){
  summaryIds=safeArr(summaryIds);
  if(!summaryIds.length)return 0;
  var hit={};
  summaryIds.forEach(function(id){hit[id]=true});
  var changed=0;
  safeArr(s.longTerms).forEach(function(lt){
    if(!lt||lt.deleted)return;
    var refs=safeArr(lt.sourceSummaryIds);
    for(var i=0;i<refs.length;i++){
      if(hit[refs[i]]){
        if(!lt.stale){
          lt.stale=true;
          lt.updatedAt=now();
          changed++;
        }
        break;
      }
    }
  });
  if(changed)markDirty(s,reason||'长期记忆待重建');
  return changed;
}

