}

function stripHtmlComments(s){
  return String(s||'').replace(/<!--[\s\S]*?-->/g,'');
}

function collectTaggedBlocks(text,names){
  var out=[];
  text=String(text||'');
  names=(names||[]).map(function(x){return String(x||'').replace(/[.*+?^${}()|[\]\\]/g,'\\$&')});
  names.forEach(function(name){
    if(!name)return;
    var re=new RegExp('<\\s*'+name+'\\b[^>]*>([\\s\\S]*?)<\\s*\\/\\s*'+name+'\\s*>','ig');
    var m;
    while((m=re.exec(text))){
      if(trim(m[1]))out.push({tag:name.toLowerCase(),body:trim(m[1]),raw:m[0]});
    }
  });
  return out;
}

function removeTaggedBlocks(text,names){
  text=String(text||'');
  names=(names||[]).map(function(x){return String(x||'').replace(/[.*+?^${}()|[\]\\]/g,'\\$&')});
  names.forEach(function(name){
    if(!name)return;
