  }
  var bodyLimit=role==='user'?1400:2200;
  state=clipMiddle(state,420,0.65);
  body=clipMiddle(body,bodyLimit,0.56);
  var parts=[];
  if(state)parts.push('【状态摘要】'+state);
  if(body)parts.push(body);
  var out=normalizeDialogueText(parts.join('\n'));
  return out||clipMiddle(raw,role==='user'?1400:2200,0.56);
}

