    var slots=idx&&Array.isArray(idx.slots)?idx.slots.map(function(x){return{L:Number(x.floorL||x.L||0)||0,index:Number(x.sourceIndex||x.index||0)||0,id:mid(x.messageId||x.id||''),msg:x.message||x.msg||null}}).filter(function(x){return x.L>0}):[];
    if(app.state&&idx&&idx.floorById)refreshMemoFloorsByMessageIds(app.state,null,null,Number(idx.totalMessages||c)||c);
    app._assistantCount=Number(idx&&idx.totalFloors||slots.length)||0;
    app._allMessagesCache=null;
