    safeArr(shared.messages).forEach(function(row){
      if(sharedTruncated)return;
      var m=row.message||row.msg||{};
      var role=String(row.role||m.role||'');
      if(role!=='assistant'&&role!=='user')return;
      var raw=row.content!=null?row.content:(m&&m.content||'');
