      var remain=sharedBudget-sharedUsed;
      if(remain<=500){sharedTruncated=true;return}
      if(cleaned.length>remain){cleaned=clipMiddle(cleaned,remain,0.55);sharedTruncated=true}
      sharedUsed+=cleaned.length;
      sharedOut.push({index:Number(row.index!=null?row.index:row.sourceIndex)||0,line:Number(row.line||0)||0,L:Number(row.L||row.floorL||0)||0,id:row.messageId||row.id||(m&&m.id),role:role,speaker:row.speaker||(role==='user'?sharedNames.userName:(sharedNames.charMap&&sharedNames.charMap[m.characterId]||sharedNames.charName||'角色')),speakerTag:role==='assistant'?('char:'+(sharedNames.charMap&&sharedNames.charMap[m.characterId]||sharedNames.charName||'角色')):('user:'+sharedNames.userName),time:row.time||msgTime(m),characterId:row.characterId||m.characterId||null,content:cleaned});
    });
    return {messages:sharedOut,startL:shared.startL,endL:shared.endL,startIndex:shared.startIndex,endIndex:shared.endIndex,names:sharedNames,truncated:!!(sharedTruncated||shared.truncated),messageIndex:shared.messageIndex||null,slots:shared.slots||[]};
  }
