  if(base.toLowerCase().slice(-3)==='/v1')return base+'/chat/completions';
  return base+'/v1/chat/completions';
}

function apiPartText(v){
  if(v==null)return '';
  if(typeof v==='string')return v;
  if(typeof v==='number'||typeof v==='boolean')return String(v);
  if(Array.isArray(v))return v.map(apiPartText).join('');
  if(typeof v==='object'){
    if(v.text!=null)return apiPartText(v.text);
    if(v.content!=null)return apiPartText(v.content);
    if(v.output_text!=null)return apiPartText(v.output_text);
    if(v.value!=null)return apiPartText(v.value);
    if(v.message!=null)return apiPartText(v.message);
  }
  return '';
}

