    resolveRunningLog(s,startText,'模型：'+model,'摘要模型已返回','ok','耗时 '+(now()-apiStart)+'ms');
    try{await save(s)}catch(_){}
    return trim(text);
  }catch(e){
    var closed=resolveRunningLog(s,startText,'模型：'+model,e&&e.name==='AbortError'?'API 请求中断':'API 请求失败','err',userErrorMessage(e,'API 请求'),e);
    if(!closed)addLogToState(s,'API 请求失败','err',userErrorMessage(e,'API 请求'),e,{step:'requesting_model',code:classifyError(e),devDetail:String(e&&e.devDetail||e&&e.responseBody||e&&e.message||e||'')});
    try{await save(s)}catch(_){}
    throw e;
  }
}

async function generateText(prompt,opt){
  opt=opt||{};
  var s=app.state||await load();
  var apiErr=null;
  var cfg=effectiveApiSettings(s);
  if(trim(cfg.apiBaseUrl)&&trim(cfg.apiKey)){
    try{return await callAPI(prompt,opt)}catch(e){if(e&&e.name==='AbortError')throw e;apiErr=e;console.warn('[第五季果汁 API fallback]',e)}
  }
  if(T.tavo&&T.tavo.generate){
    var localText=trim(await T.tavo.generate(prompt,{context:false}));
    if(localText)return localText;
    if(apiErr)throw apiErr;
    throw new Error('模型没有返回可用内容');
  }
  if(apiErr)throw apiErr;
  throw new Error('没有可用生成接口');
}

function retryableGenerateError(e){
  var code=classifyError(e);

  if(code==='api_timeout'||code==='rate_limit'||code==='server_error'||code==='network_error')return true;

  var msg=String(e&&e.message||e||'').toLowerCase();
  if(e&&e.name==='AbortError')return false;
  return msg.indexOf('network')>=0||msg.indexOf('fetch')>=0||msg.indexOf('timeout')>=0||msg.indexOf('failed')>=0||msg.indexOf('429')>=0||msg.indexOf('500')>=0||msg.indexOf('502')>=0||msg.indexOf('503')>=0||msg.indexOf('504')>=0;
}

async function generateTextRetry(prompt,opt,s,label){
  opt=opt||{};
  var tries=opt.retries==null?2:Math.max(0,Number(opt.retries)||0);
  var lastErr=null;
  for(var i=0;i<=tries;i++){
    try{return await generateText(prompt,opt)}catch(e){
      lastErr=e;
      if(e&&e.name==='AbortError')throw e;
      if(!retryableGenerateError(e)||i>=tries)throw e;
      if(s)addLogToState(s,(label||'生成')+'重试','err','第 '+(i+1)+' 次失败，准备重试：'+userErrorMessage(e,label||'生成'),e,{step:'requesting_model',code:classifyError(e),devDetail:String(e&&e.devDetail||e&&e.responseBody||e&&e.message||e||'')});
      try{await save(s||app.state)}catch(_saveRetryErr){}
      await new Promise(function(resolve){setTimeout(resolve,700*(i+1))});
    }
  }
  throw lastErr;
}

