function isPlaceholderText(text){
  var t=sig(text);
  return !t||t==='阶段总结'||t==='短期总结'||t==='总结'||t==='长期记忆'||t==='历史总览'||t==='前情提要'||t==='暂无'||t==='无'||t==='null'||t==='undefined';
}

// 只保留英文/技术性报错特征词（模型与中转站报错的典型输出），
// 去掉“网络错误/稍后重试/请求失败/超时/模型忙”等容易在中文剧情总结里正常出现的词。
// 并从“命中即死”改为“占主体才判废”：多次命中，或短文本且开头就命中。
function containsBadResult(text){
  text=String(text||'');
  var re=/(rate\s*limit|too\s*many\s*requests|api\s*返回|api\s*fail|error\s*[:：]|traceback|stack\s*trace|network\s*error|request\s*failed|timed?\s*out|invalid\s*api|unauthorized|forbidden|service\s*unavailable|internal\s*server\s*error|bad\s*gateway|proxy\s*error|gateway\s*time-?out|overloaded)/i;
  var hits=(text.match(new RegExp(re.source,'gi'))||[]).length;
  if(hits>=2)return true;
  if(hits===1&&text.length<160)return re.test(text.slice(0,40));
  return false;
}

// 细分失败原因，避免“格式不符合记忆要求”一句话糊掉所有情况。
// 返回：''（合格）/ 'placeholder' / 'looks_like_error' / 'too_short' / 'missing_sections'
function classifySummaryBody(text,sectionKeys){
  var t=trim(text);
  if(!t)return 'placeholder';
  if(isPlaceholderText(t))return 'placeholder';
  if(containsBadResult(t))return 'looks_like_error';
  if(t.length<60)return 'too_short';
  var hits=0;
  safeArr(sectionKeys).forEach(function(v){if(t.indexOf(v)>=0)hits++});
  return hits>=2?'':'missing_sections';
}

function validSummaryBody(text){
  return !classifySummaryBody(text,['时间锚点','关键事件','关系','角色','用户','待解决','可回调']);
}

function validLongTermBody(text){
  return !classifySummaryBody(text,['时间线','关键事件','关系状态','角色长期档案','用户长期画像','待继承上下文']);
}

function validHistoryOverviewBody(text){
  var t=trim(text);
  if(isPlaceholderText(t)||containsBadResult(t)||t.length<80)return false;
  return /(1L|楼层|阶段|前情|历史|关系|事件)/.test(t);
}

function extractSectionTitle(text){
  var t=trim(text);
  var m=t.match(/【标题】\s*\n+([^\n]+)/);
  if(m&&trim(m[1]))return trim(m[1]).replace(/^[-：:\s]+/,'');
  m=t.match(/^#?\s*([^\n]{2,42})/);
  return m?trim(m[1]).replace(/^【标题】/,''):'';
}

function parseSummaryResult(text,fallbackTitle){
  var raw=trim(text);
  var title=extractSectionTitle(raw);
  if(isPlaceholderText(title))title='';
  var code=classifySummaryBody(raw,['时间锚点','关键事件','关系','角色','用户','待解决','可回调']);
  if(code){
    var err=new Error('模型 返回了无效阶段总结['+code+']：'+clip(raw||'(空)',80));
    err.parseCode=code;
    err.modelReturn=raw;
    throw err;
  }
  return {title:clip(title||fallbackTitle||'阶段总结',42),summary:raw};
}

function extractNamedSection(text,name){
  text=String(text||'');
  var re=new RegExp('【'+name+'】([\\s\\S]*?)(?=\\n【[^】]+】|$)');
  var m=text.match(re);
  return m?trim(m[1]||''):'';
}
function parseFloorRangeFromText(text,fallbackStart,fallbackEnd){
  var t=String(text||'');
  var m=t.match(/(\d+)\s*L\s*[-~—至到]\s*(\d+)\s*L/i)||t.match(/楼层[:：]?\s*(\d+)\s*L\s*[-~—至到]\s*(\d+)\s*L/i);
  if(m)return{startL:Number(m[1]||0)||fallbackStart,endL:Number(m[2]||0)||Number(m[1]||0)||fallbackEnd};
  m=t.match(/(\d+)\s*L/i);
  if(m)return{startL:Number(m[1]||0)||fallbackStart,endL:Number(m[1]||0)||fallbackEnd};
  return{startL:fallbackStart,endL:fallbackEnd};
}
function pendingLineTitle(line){
  line=trim(line).replace(/^[-*•\s]+/,'');
  line=line.replace(/^\[[^\]]+\]\s*/,'').replace(/^【[^】]+】\s*/,'');
  return clip(line.split(/[。；;，,]/)[0]||line,42)||'待解决事件';
}
function applyPendingFromSummary(s,item,summaryText,bundle){
  s.pendingThreads=safeArr(s.pendingThreads).map(normalizePendingThread);
  s.pendingThreads=s.pendingThreads.filter(function(x){return x&&x.createdFromSummaryId!==item.id});
  var section=extractNamedSection(summaryText,'待解决与可回调细节');
  if(!section||/^无[。.\s]*$/.test(section)||/暂无/.test(section))return false;
  var lines=section.split(/\n+/).map(function(x){return trim(x)}).filter(Boolean);
  if(!lines.length)lines=[section];
  var changed=false;
  lines.slice(0,8).forEach(function(line){
    if(!line||/^无[。.\s]*$/.test(line)||/暂无/.test(line))return;
    var r=parseFloorRangeFromText(line,Number(item.startL||0)||Number(bundle&&bundle.startL||0)||0,Number(item.endL||0)||Number(bundle&&bundle.endL||0)||0);
    var detail=clip(line.replace(/^[-*•\s]+/,''),240);
    var key=sig(detail);
    if(!key)return;
    var exists=s.pendingThreads.some(function(x){return x&&['open','due_unconfirmed','rescheduled','uncertain'].indexOf(x.status)>=0&&sig(x.detail||'')===key});
    if(exists)return;
    s.pendingThreads.push(normalizePendingThread({status:'open',title:pendingLineTitle(line),detail:detail,createdFromSummaryId:item.id,startL:r.startL,endL:r.endL,startMessageId:assistantMessageIdForL(bundle,r.startL),endMessageId:assistantMessageIdForL(bundle,r.endL),evidence:[detail],createdAt:now(),updatedAt:now()}));
    changed=true;
  });
  return changed;
}

function parseLongTermResult(text,fallbackTitle){
  var raw=trim(text);
  var title=extractSectionTitle(raw);
  if(isPlaceholderText(title))title='';
  var code=classifySummaryBody(raw,['时间线','关键事件','关系状态','角色长期档案','用户长期画像','待继承上下文']);
  if(code){
    var err=new Error('模型 返回了无效长期记忆['+code+']：'+clip(raw||'(空)',80));
    err.parseCode=code;
    err.modelReturn=raw;
    throw err;
  }
  return {title:clip(title||fallbackTitle||'长期记忆',42),content:raw};
}

function parseHistoryOverviewResult(text,fallbackTitle){
  var raw=trim(text);
  var title=extractSectionTitle(raw);
  if(isPlaceholderText(title))title='';
  var code;
  var t=trim(raw);
  if(!t)code='placeholder';
  else if(isPlaceholderText(t))code='placeholder';
  else if(containsBadResult(t))code='looks_like_error';
  else if(t.length<80)code='too_short';
  else if(!/(1L|楼层|阶段|前情|历史|关系|事件)/.test(t))code='missing_sections';
  else code='';
  if(code){
    var err=new Error('模型 返回了无效历史总览['+code+']：'+clip(raw||'(空)',80));
    err.parseCode=code;
    err.modelReturn=raw;
    throw err;
  }
  return {title:clip(title||fallbackTitle||'历史总览',42),content:raw};
}

