function normalizeTaskText(s){
  return trim(s||'');
}

function taskLabel(type,meta){
  meta=meta||{};
  if(type==='summary')return '短期总结';
  if(type==='manual_backfill')return '指定补录';
  if(type==='backfill')return '历史补录';
