  if(type==='rebuild_history')return '重建历史总览';
  if(type==='sync_worldbook')return '同步世界书';
  return '任务';
}

function setTaskState(s,type,meta){
  meta=meta||{};
  s.runtimeTask={
    active:meta.active!==false,
    finished:false,
    success:false,
    type:type||'task',
    label:taskLabel(type,meta),
    startedAt:now(),
    updatedAt:now(),
    allowPause:!!meta.allowPause,
    allowCancel:!!meta.allowCancel,
    rangeText:normalizeTaskText(meta.rangeText),
    currentText:normalizeTaskText(meta.currentText),
    resultText:'',
    progressText:normalizeTaskText(meta.currentText),
    detail:normalizeTaskText(meta.rangeText||meta.currentText)
  };
}

function updateTaskState(s,patch){
  s.runtimeTask=s.runtimeTask&&typeof s.runtimeTask==='object'?s.runtimeTask:{
    active:true,
    finished:false,
    success:false,
    type:'task',
    label:'任务',
    startedAt:now(),
    updatedAt:now(),
    allowPause:false,
    allowCancel:false,
    rangeText:'',
    currentText:'',
    resultText:'',
    progressText:'',
    detail:''
  };
  patch=patch||{};
  Object.keys(patch).forEach(function(k){
    s.runtimeTask[k]=patch[k];
  });

  if(patch.progressText!=null && patch.currentText==null){
    s.runtimeTask.currentText=normalizeTaskText(patch.progressText);
  }
  if(patch.detail!=null && patch.rangeText==null && !s.runtimeTask.rangeText){
    s.runtimeTask.rangeText=normalizeTaskText(patch.detail);
  }

  s.runtimeTask.progressText=normalizeTaskText(s.runtimeTask.currentText);
  s.runtimeTask.detail=normalizeTaskText(s.runtimeTask.resultText||s.runtimeTask.rangeText||s.runtimeTask.currentText);
  s.runtimeTask.updatedAt=now();
}

function finishTaskState(s,ok,resultText){
  s.runtimeTask=s.runtimeTask&&typeof s.runtimeTask==='object'?s.runtimeTask:{
    active:false,
    finished:true,
    success:!!ok,
    type:'task',
    label:'任务',
    startedAt:now(),
    updatedAt:now(),
    allowPause:false,
    allowCancel:false,
    rangeText:'',
    currentText:'',
    resultText:'',
    progressText:'',
    detail:''
  };
  s.runtimeTask.active=false;
  s.runtimeTask.finished=true;
  s.runtimeTask.success=!!ok;
  s.runtimeTask.resultText=normalizeTaskText(resultText||s.runtimeTask.resultText||'任务已结束');
  s.runtimeTask.currentText='';
  s.runtimeTask.progressText='';
  s.runtimeTask.detail=s.runtimeTask.resultText;
  s.runtimeTask.updatedAt=now();
}

function clearTaskState(s){
