async function setMemoInjectBinding(enabled,s){
  s=s||await load();
  try{
    var chat=await hostCall(function(){return T.tavo.chat.current()},'chat.current.memo.master',8000,{silent:true,fallback:null});
    if(!chat)return false;
    chat.lorebooks=Array.isArray(chat.lorebooks)?chat.lorebooks:[];
    var bid=s.sync&&s.sync.injectBookId;
    if(enabled&&!bid){
      await ensureInjectBook(s);
      s=await load();
      bid=s.sync&&s.sync.injectBookId;
    }
    var target=String(bid||'');
    var seen={},changed=false;
    chat.lorebooks=chat.lorebooks.filter(function(x){
      var k=String(x&&x.id||'');
      if(!k)return false;
      if(target&&k===target&&!enabled){changed=true;return false}
      if(seen[k]){changed=true;return false}
      seen[k]=true;
      return true;
    });
    if(enabled&&target){
      var has=chat.lorebooks.some(function(x){return String(x&&x.id||'')===target});
      if(!has){
        var book=await hostCall(function(){return T.tavo.lorebook.get(target)},'lorebook.get.memo.master',12000,{silent:true,fallback:null});
        if(book&&book.id!=null){
          chat.lorebooks.push({id:book.id,name:book.name||'记忆系统注入书'});
          changed=true;
        }
      }
    }
    if(changed)await hostCall(function(){return T.tavo.chat.update(chat)},'chat.update.memo.master',12000,{silent:true,fallback:null});
    return true;
  }catch(_){return false}
}

async function updateHistoryOverviewIfNeeded(s,reason,force){
  var plan=buildInjectPlan(s);
  var desiredEnd=Number(plan.desiredHistoryEnd||0)||0;
  var current=s.historyOverview;
  if(desiredEnd<=0){
    if(current){
      s.historyOverview=null;
      markDirty(s,'移除历史总览');
    }
    return false;
  }
  var currentEnd=Number(current&&current.endL||0)||0;
  if(!force&&currentEnd===desiredEnd)return false;
  if(!force&&currentEnd>0&&desiredEnd<currentEnd)return false;
  var source=activeSummariesSorted(s).filter(function(x){return Number(x.endL||0)<=desiredEnd});
  var continuousEnd=findContinuousCoveredEnd(source,1);
  if(continuousEnd!==desiredEnd)return false;
  var data=await generateHistoryOverviewData(source,s,1,desiredEnd,{fallbackTitle:'历史总览 1L-'+desiredEnd+'L',abortKey:'_scanAbort'});
  s.historyOverview={
    id:current&&current.id||uid('hov'),
    startL:1,
    endL:desiredEnd,
    startMessageId:mid(source[0]&&source[0].startMessageId||''),
    endMessageId:mid(source[source.length-1]&&source[source.length-1].endMessageId||''),
    title:clip(data.title||('历史总览｜1L-'+desiredEnd+'L'),42),
    content:trim(data.content),
    createdAt:current&&current.createdAt||now(),
    updatedAt:now(),
    sourceSummaryIds:source.map(function(x){return x.id}),
    sourceSummaryHash:hashText(source.map(function(x){return x.id+':'+x.sourceHash}).join('|')),
    version:VER,
    frozen:true,
    manualRebuiltAt:force?now():0
  };
  markDirty(s,reason||'更新历史总览');
  addLogToState(s,'历史总览更新','ok','覆盖 1L-'+desiredEnd+'L');
  return true;
}

async function maybeAutoCreateLongTerms(s){
  var rounds=Math.max(2,Number(s.settings.longTermRounds||3)||3);
  var created=0;

  var sums=activeSummariesSorted(s).filter(function(x){
    return !x.deleted && Number(x.startL||0)>0;
  });

  if(!sums.length)return 0;

  for(var i=0;i<sums.length;i+=rounds){
    var block=sums.slice(i,i+rounds);
    if(block.length!==rounds)continue;

    var ok=true;
    for(var j=1;j<block.length;j++){
      var prevEnd=Number(block[j-1].endL||0)||0;
      var curStart=Number(block[j].startL||0)||0;
      if(curStart!==prevEnd+1){
        ok=false;
        break;
      }
    }
    if(!ok)continue;

    var startL=Number(block[0].startL||0)||0;
    var endL=Number(block[block.length-1].endL||0)||0;
    var startMessageId=mid(block[0].startMessageId||'');
    var endMessageId=mid(block[block.length-1].endMessageId||'');
    var ids=block.map(function(x){return x.id});
    var idsKey=ids.join('|');

    var target=safeArr(s.longTerms).find(function(lt){
      return lt && !lt.deleted && safeArr(lt.sourceSummaryIds).join('|')===idsKey;
    }) || safeArr(s.longTerms).find(function(lt){
      return lt && !lt.deleted &&
        Number(lt.startL||0)===startL &&
        Number(lt.endL||0)===endL;
    }) || safeArr(s.longTerms).find(function(lt){
      return lt && !lt.deleted && !!lt.stale &&
        Number(lt.startL||0)===startL &&
        Number(lt.endL||0)===endL;
    });

    if(target && !target.stale && safeArr(target.sourceSummaryIds).join('|')===idsKey){
      continue;
    }

    var ld=await generateLongTermData(block,s,{
      fallbackTitle:'长期记忆 '+startL+'L-'+endL+'L',
      abortKey:'_scanAbort'
    });

    if(target){
      pushRevision(target);
      target.startL=startL;
      target.endL=endL;
      target.startMessageId=startMessageId;
      target.endMessageId=endMessageId;
      target.title=clip(ld.title||'长期记忆',42);
      target.content=trim(ld.content);
      target.updatedAt=now();
      target.deleted=false;
      target.generationMode='auto';
      target.sourceSummaryIds=ids;
      target.sourceSummaryHash=hashText(idsKey);
      target.ruleSnapshot=blockRuleSnapshot(block);
      target.version=VER;
      target.windowEligible=true;
      target.stale=false;
    }else{
      s.longTerms.push(normalizeLongTermItem({
        id:uid('lt'),
        startL:startL,
        endL:endL,
        startMessageId:startMessageId,
        endMessageId:endMessageId,
        title:clip(ld.title||'长期记忆',42),
        content:trim(ld.content),
        createdAt:now(),
        updatedAt:now(),
        deleted:false,
        generationMode:'auto',
        sourceSummaryIds:ids,
        sourceSummaryHash:hashText(idsKey),
        ruleSnapshot:blockRuleSnapshot(block),
        version:VER,
        windowEligible:true,
        stale:false
      },0,s));
    }

    addLogToState(s,'长期记忆升级','ok',startL+'L-'+endL+'L');
    markDirty(s,'新增长期记忆');
    created++;
  }

  return created;
}





function blockRuleSnapshot(block){
  var first=block&&block[0]||{};
  return first.ruleSnapshot||buildRuleSnapshot(app.state||{});
}
function collectLongTermBlocksInRange(s,fromL,toL){
  var rounds=Math.max(2,Number(s.settings.longTermRounds||3)||3);
  var list=activeSummariesSorted(s).filter(function(x){
    var st=Number(x.startL||0)||0;
    var ed=Number(x.endL||0)||0;
    return st>=fromL && ed<=toL;
  }).slice().sort(function(a,b){
    var as=Number(a.startL||0)||0, bs=Number(b.startL||0)||0;
    if(as!==bs)return as-bs;
    return (Number(a.endL||0)||0)-(Number(b.endL||0)||0);
  });

  var blocks=[];
  for(var i=0;i+rounds-1<list.length;i+=rounds){
    var block=list.slice(i,i+rounds);
    if(block.length!==rounds)break;

    var ok=true;
    for(var j=1;j<block.length;j++){
      var prevEnd=Number(block[j-1].endL||0)||0;
      var curStart=Number(block[j].startL||0)||0;
      if(curStart!==prevEnd+1){
        ok=false;
        break;
      }
    }
    if(!ok)continue;

    blocks.push(block);
  }
  return blocks;
}

async function runSummary(opt){
  opt=opt||{};
    var s=await load();
  var cur=await countAssistant(true);
  var idx=await platformMessageIndexLatest(false);
  if(idx&&idx.floorById)refreshMemoFloorsByMessageIds(s,null,null,Number(idx.totalMessages||0)||0);
  var fromBackfill=!!opt.fromBackfill;
  var summaryCommitted=false;


  if(!s.meta.started){toast('请先从当前楼层后开始记录');return null}
  if(s.scan.busy && !fromBackfill){toast('当前已有任务在运行');return null}
  if(s.runtimeTask&&s.runtimeTask.active&&!fromBackfill){toast('已有任务正在执行');return null}

  var interval=Math.max(8,Number(s.settings.summaryIntervalL||24)||24);
  var fromL,toL;

  if(opt.fromL!=null&&opt.toL!=null){
    fromL=Math.max(1,Number(opt.fromL)||1);
    toL=Math.max(fromL,Math.min(cur,Number(opt.toL)||fromL));
  }else{
    fromL=Math.max(1,(Number(s.progress.processedL||0)||0)+1);
    toL=Math.min(cur,fromL+interval-1);
    if(toL<fromL){toast('没有新的模型 回复');return null}
    if(toL-fromL+1<interval&&!opt.manual){return null}
    if(toL-fromL+1<5&&opt.manual&&!fromBackfill){toast('当前内容过少，建议再聊一会');return null}
  }

  if(opt.manual&&opt.allowShortManualRange){
    if(toL<fromL){toast('指定区间无可用楼层');return null}
  }

  if(hasExactSummaryRange(s,fromL,toL)){toast('该区间已有总结');return null}

  var runningText=fromBackfill?'补录分段生成':'生成短期总结';
  var runningDetail=fromL+'L-'+toL+'L';
  s.scan=s.scan||{};
  s.scan.lastAttemptFromL=fromL;
  s.scan.lastAttemptToL=toL;
  s.scan.lastStep='summary_generating';

  if(!fromBackfill){
    toast('已开始生成短期总结');
    setScanState(s,'summary',true);
        setTaskState(s,'summary',{
      rangeText:runningDetail,
      currentText:'正在生成短期总结',
      allowPause:true,
      allowCancel:true
    });

    addLogToState(s,runningText,'running',runningDetail,null,{step:'summary_generating'});
    await save(s);
    renderAll(true);
  }else{
    s.scan.lastActiveAt=now();
        updateTaskState(s,{
      rangeText:runningDetail,
      currentText:'正在补录该分段'
    });

    addLogToState(s,runningText,'running',runningDetail,null,{step:'summary_generating'});
    await save(s);
  }

  try{
    var bundle=await collectRange(fromL,toL);
    if(!bundle.messages.length)throw new Error('无可整理消息');

    var summaryRetries=fromBackfill
      ? Math.max(0,Number(s.settings&&s.settings.backfillRetryLimit||0)||0)
      : 2;

    if(bundle.truncated){
      addLogToState(s,'原文采集已截断','err',fromL+'L-'+toL+'L 原文过长，已压缩采样',null,{step:'collecting_messages'});
      await save(s);
    }

    var sd=await generateSummaryData(bundle,s,{
      fallbackTitle:'阶段总结 '+fromL+'L-'+toL+'L',
      abortKey:'_scanAbort',
      retries:summaryRetries
    });

    var item=normalizeSummaryItem({
      id:uid('sum'),
      startL:fromL,
      endL:toL,
      startMessageId:assistantMessageIdForL(bundle,fromL),
      endMessageId:assistantMessageIdForL(bundle,toL),
      title:sd.title,
      summary:sd.summary,
      content:sd.summary,
      createdAt:now(),
      updatedAt:now(),
      deleted:false,
      generationMode:fromBackfill?'manual_backfill':(opt.manual?'manual_summary':'auto'),
      ruleSnapshot:buildRuleSnapshot(s),
      version:VER
    },0,s);

    applyPendingFromSummary(s,item,sd.summary,bundle);
    s.summaries.push(item);
    updateProgressFromSummaries(s);
    detectUnrecordedRanges(s,cur);

    if(!fromBackfill){
      setScanState(s,null,false);
      finishTaskState(s,true,'短期总结已完成');
    }else{
      s.scan.lastActiveAt=now();
    }

    markDirty(s,'新增短期总结');

    resolveRunningLog(
      s,
      runningText,
      runningDetail,
      fromBackfill?'补录分段完成':'短期总结完成',
      'ok',
      runningDetail
    );

    // 先把短期总结本身落库，后面长期记忆 / 历史总览失败也不回滚这一步
    await save(s);
    summaryCommitted=true;

    if(!fromBackfill){
      try{
        await maybeAutoCreateLongTerms(s);
        await updateHistoryOverviewIfNeeded(s,'更新历史总览',false);
        await save(s);
      }catch(postErr){
        logErrorToState(
          s,
          '后续记忆整理失败',
          postErr,
          userErrorMessage(postErr,'后续记忆整理'),
          {step:'post_summary'}
        );
        await save(s);
      }
    }


        if(!fromBackfill){
      s=await load();
      try{
        setTaskState(s,'sync_worldbook',{
          rangeText:runningDetail,
          currentText:'正在同步世界书',
          allowPause:false,
          allowCancel:false
        });

        await save(s);
        await syncInjectBook(s,'summary');

        s=await load();
        finishTaskState(s,true,'短期总结已完成，并已同步世界书');
        await save(s);

      }catch(syncErr){
        logErrorToState(s,'同步失败',syncErr,userErrorMessage(syncErr,'世界书同步'),{step:'worldbook_syncing'});
        finishTaskState(s,false,'短期总结已完成，但世界书同步失败');
        await save(s);
      }
    }


    if(!fromBackfill)toast('短期总结已完成');
    renderAll(true);
    return item;
  }catch(e){
    if(e&&e.name==='AbortError'){
      await refreshScanState(s);
      if(s.scan.cancelRequested){
        setScanState(s,null,false);
        s.scan.cooldownUntil=now()+60000;
        finishTaskState(s,false,'任务已取消');

        resolveRunningLog(
          s,
          runningText,
          runningDetail,
          fromBackfill?'补录分段已取消':'短期总结已取消',
          'ok',
          runningDetail
        );

        addLogToState(s,'任务已取消','ok','用户取消',null,{step:'cancelled'});
      }else if(s.scan.userPauseRequested){
        s.scan.busy=false;
        s.scan.paused=true;
        s.scan.type=fromBackfill?'manual_backfill':'summary';
        updateTaskState(s,{
          active:true,
          finished:false,
          success:false,
          currentText:'任务已暂停'
        });

        resolveRunningLog(
          s,
          runningText,
          runningDetail,
          fromBackfill?'补录分段已暂停':'短期总结已暂停',
          'ok',
          runningDetail
        );
        addLogToState(s,'任务已暂停','ok','用户主动暂停，可在任务中心继续。',null,{step:'paused',code:'user_pause'});
      }else{
        markRecoverableInterrupt(s,e,'summary_generating');
        finishTaskState(s,false,'请求被中断，可稍后继续');
        resolveRunningLog(
          s,
          runningText,
          runningDetail,
          fromBackfill?'补录分段已中断':'短期总结已中断',
          'err',
          s.scan.lastErrorText,
          e
        );
        logErrorToState(s,fromBackfill?'补录分段中断':'短期总结中断',e,s.scan.lastErrorText,{step:'summary_generating'});
      }
      await save(s);
      toast(s.scan.paused?'任务已暂停':(s.scan.recoverable?s.scan.lastErrorText:'任务已取消'));
      renderAll(true);
      return null;
    }

        if(!summaryCommitted){
      // 记录细分失败原因码与模型实际返回，便于排查“为何总结失败”
      var frCode=classifyError(e);
      if(e&&e.parseCode){frCode='format_error'}
      var frReason=userErrorMessage(e,'生成');
      var frRaw='';
      if(e&&e.parseCode){frRaw=String(e.modelReturn||'')}
      else{
        // 非校验类失败也尽量保留一点错误原文
        frRaw=String(e&&(e.responseBody||e.devDetail||e.message||e)||'');
      }
      s.failedRanges.push(normalizeFailedRange({
        startL:fromL,
        endL:toL,
        reason:frReason,
        code:frCode+(e&&e.parseCode?('/'+e.parseCode):''),
        lastRaw:frRaw
      }));

      if(!fromBackfill){
        setScanState(s,null,false);
        finishTaskState(s,false,'短期总结失败');
      }else{
        s.scan.lastActiveAt=now();
      }

      resolveRunningLog(
        s,
        runningText,
        runningDetail,
        fromBackfill?'补录分段失败':'短期总结失败',
        'err',
        clip(frReason,80),
        e
      );

      await save(s);

      if(!fromBackfill)toast(frReason);
    }else{
      if(!fromBackfill){
        setScanState(s,null,false);
        finishTaskState(s,false,'短期总结已保存，但后续整理失败');
      }else{
        s.scan.lastActiveAt=now();
      }

      logErrorToState(
        s,
        '后续记忆整理失败',
        e,
        userErrorMessage(e,'后续记忆整理'),
        {step:'post_summary'}
      );

      await save(s);

      if(!fromBackfill)toast(userErrorMessage(e,'后续记忆整理'));
    }

    renderAll(true);
    return null;

  }
}



