async function runBackfillRange(fromL,toL){
  var s=await load();
  if(!s.meta.started){toast('请先在首页点“从当前楼层后开始记录”');return null}
  if(s.scan.busy){toast('当前已有任务在运行');return null}
  if(s.runtimeTask&&s.runtimeTask.active){toast('已有任务正在执行');return null}

  fromL=Math.max(1,Number(fromL)||1);
  toL=Math.max(fromL,Number(toL)||fromL);

  var interval=Math.max(8,Number(s.settings.summaryIntervalL||24)||24);
  var count=0;

  setScanState(s,'manual_backfill',true);
  s.scan.rangeFromL=fromL;
  s.scan.rangeToL=toL;
  s.scan.rangeCurrentL=fromL;
  s.scan.lastSafeL=Math.max(0,fromL-1);
  s.scan.lastAttemptFromL=fromL;
  s.scan.lastAttemptToL=0;

  setTaskState(s,'manual_backfill',{
    rangeText:fromL+'L - '+toL+'L',
    currentText:'准备开始补录',
    allowPause:true,
    allowCancel:true
  });

  addLogToState(s,'指定补录开始','running',fromL+'L-'+toL+'L',null,{step:'manual_backfill'});
  await save(s);
  renderAll(true);

  try{
    var segments=getMissingSegmentsInRange(s,fromL,toL,interval);

    if(!segments.length){
      setScanState(s,null,false);
      finishTaskState(s,true,'该范围内没有缺失分段');
      await save(s);
      toast('该范围内没有缺失分段');
      renderAll(true);
      return 0;
    }

    for(var si=0;si<segments.length;si++){
      s=await load();
      await refreshScanState(s);
      if(s.scan.cancelRequested||s.scan.paused||s.scan.recoverable)break;

      var seg=segments[si];
      var cur=seg.startL;
      var end=seg.endL;

      s.scan.rangeCurrentL=cur;
      s.scan.lastAttemptFromL=cur;
      s.scan.lastAttemptToL=end;

      updateTaskState(s,{
        rangeText:fromL+'L - '+toL+'L',
        currentText:'正在补录 '+cur+'L - '+end+'L'
      });
      await save(s);

      var created=await runSummary({
        manual:true,
        fromL:cur,
        toL:end,
        fromBackfill:true,
        allowShortManualRange:true
      });

      s=await load();
      if(s.scan&&s.scan.recoverable){
        updateTaskState(s,{currentText:'补录已中断，可在任务中心继续'});
        await save(s);
        break;
      }

      if(created){
        count++;
        s.scan.lastSafeL=end;
        resolveFailedRangesByCoverage(s,cur,end);
      }

      s.scan.lastActiveAt=now();
      await save(s);
    }

    s=await load();

    if(s.scan.cancelRequested){
      setScanState(s,null,false);
      s.scan.cooldownUntil=now()+60000;
      finishTaskState(s,false,'补录已取消');
      resolveRunningLog(s,'指定补录开始',fromL+'L-'+toL+'L','指定补录已取消','ok','补录已取消');
      await save(s);
      toast('补录已取消');
      renderAll(true);
      return count;
    }

    if(s.scan.recoverable){
      s.scan.busy=false;
      updateTaskState(s,{active:true,finished:false,success:false,currentText:'补录已中断，可在任务中心继续'});
      resolveRunningLog(s,'指定补录开始',fromL+'L-'+toL+'L','指定补录已中断','err','补录任务已中断，可在任务中心继续');
      await save(s);
      toast('补录任务已中断，可在任务中心继续');
      renderAll(true);
      return count;
    }

    if(s.scan.paused){
      s.scan.busy=false;
      updateTaskState(s,{currentText:'补录已暂停'});
      resolveRunningLog(s,'指定补录开始',fromL+'L-'+toL+'L','指定补录已暂停','ok','补录已暂停');
      await save(s);
      toast('补录已暂停');
      renderAll(true);
      return count;
    }

    // 用最新状态统一结算
    s=await load();
    await maybeAutoCreateLongTerms(s);
    await updateHistoryOverviewIfNeeded(s,'补录后更新历史总览',false);
    await save(s);

    s=await load();
    setTaskState(s,'sync_worldbook',{
      rangeText:fromL+'L - '+toL+'L',
      currentText:'正在同步世界书',
      allowPause:false,
      allowCancel:false
    });
    await save(s);

    try{
      await syncInjectBook(s,'backfill-finished');
      s=await load();
      var newFailed=safeArr(s.failedRanges).filter(function(x){return !x.resolved}).length;
      finishTaskState(s,true,'补录完成，共 '+count+' 段；剩余失败 '+newFailed+' 段');
      setScanState(s,null,false);
      s.scan.rangeFromL=0;
      s.scan.rangeToL=0;
      s.scan.rangeCurrentL=0;
      resolveRunningLog(s,'指定补录开始',fromL+'L-'+toL+'L','指定补录完成','ok','补录完成，共 '+count+' 段；剩余失败 '+newFailed+' 段');
      await save(s);
      toast('补录完成，共 '+count+' 段');
    }catch(syncErr){
      s=await load();
      logErrorToState(s,'世界书同步失败',syncErr,userErrorMessage(syncErr,'世界书同步'),{step:'worldbook_syncing'});
      finishTaskState(s,false,'补录已完成，但世界书同步失败');
      resolveRunningLog(s,'指定补录开始',fromL+'L-'+toL+'L','指定补录完成但同步失败','err','补录已完成，但世界书同步失败');
      setScanState(s,null,false);
      await save(s);
      toast('补录已完成，但世界书同步失败');
    }

    renderAll(true);
    return count;
  }catch(e){
    s=await load();
    setScanState(s,null,false);
    finishTaskState(s,false,'补录失败');
    resolveRunningLog(s,'指定补录开始',fromL+'L-'+toL+'L','指定补录失败','err',userErrorMessage(e,'补录'),e);
    logErrorToState(s,'指定补录失败',e,userErrorMessage(e,'补录'),{step:'failed'});
    await save(s);
    toast(userErrorMessage(e,'补录'));
    renderAll(true);
    return null;
  }
}


async function runBackfill(){
  var s=await load();
  var cur=await countAssistant(true);
  var end=Math.max(1,Number(s.progress.baselineL||cur)||cur);
  var start=Math.max(1,(Number(s.progress.backfillProcessedL||0)||0)+1);
  if(start>end){toast('没有历史内容需要补录');return null}
  return runBackfillRange(start,end);
}

async function rebuildLongTermRange(fromL,toL){
  var s=await load();

  if(s.scan&&s.scan.busy){
    toast('当前有任务在运行');
    return null;
  }
  if(s.runtimeTask&&s.runtimeTask.active){
    toast('已有任务正在执行');
    return null;
  }

  fromL=Math.max(1,Number(fromL||1)||1);
  toL=Math.max(fromL,Number(toL||fromL)||fromL);

  if(!fromL||!toL||toL<fromL){
    toast('请输入有效的长期记忆范围');
    return null;
  }

  var blocks=collectLongTermBlocksInRange(s,fromL,toL);
  if(!blocks.length){
    toast('该范围内没有可用于生成长期记忆的完整短期分组');
    return null;
  }

  setTaskState(s,'rebuild_long',{
    rangeText:fromL+'L - '+toL+'L',
    currentText:'正在扫描并重建长期记忆',
    allowPause:false,
    allowCancel:false
  });
  await save(s);
  renderAll(true);

  var rebuilt=0;
  var skipped=0;

  try{
    for(var bi=0;bi<blocks.length;bi++){
      s=await load();
      var block=blocks[bi];
      var startL=Number(block[0].startL||0)||0;
      var endL=Number(block[block.length-1].endL||0)||0;
      var startMessageId=mid(block[0].startMessageId||'');
      var endMessageId=mid(block[block.length-1].endMessageId||'');
      var ids=block.map(function(x){return x.id});

      updateTaskState(s,{
        rangeText:fromL+'L - '+toL+'L',
        currentText:'正在处理 '+startL+'L - '+endL+'L'
      });
      await save(s);

      var existed=safeArr(s.longTerms).find(function(x){
        if(!x||x.deleted)return false;
        return Number(x.startL||0)===startL && Number(x.endL||0)===endL;
      });

      var ld=await generateLongTermData(block,s,{
        fallbackTitle:'长期记忆 '+startL+'L-'+endL+'L',
        abortKey:'_scanAbort'
      });

      var newTitle=clip(trim(ld.title||''),42);
      var newContent=trim(ld.content||'');

      if(!newContent || !validLongTermBody(newContent)){
        addLogToState(s,'长期记忆重建失败','err',startL+'L-'+endL+'L · 返回无效内容');
        await save(s);
        skipped++;
        continue;
      }

      if(!newTitle || sig(newTitle)==='标题' || sig(newTitle)==='长期记忆' || sig(newTitle)==='【标题】'){
        newTitle=clip(extractSectionTitle(newContent)||('长期记忆 '+startL+'L-'+endL+'L'),42);
      }

      if(existed){
        pushRevision(existed);
        existed.title=newTitle;
        existed.content=newContent;
        existed.updatedAt=now();
        existed.deleted=false;
        existed.startMessageId=startMessageId;
        existed.endMessageId=endMessageId;
        existed.sourceSummaryIds=ids;
        existed.sourceSummaryHash=hashText(ids.join('|'));
        existed.ruleSnapshot=blockRuleSnapshot(block);
        existed.version=VER;
        existed.windowEligible=true;
        existed.stale=false;
      }else{
        s.longTerms.push(normalizeLongTermItem({
          id:uid('lt'),
          startL:startL,
          endL:endL,
          startMessageId:startMessageId,
          endMessageId:endMessageId,
          title:newTitle,
          content:newContent,
          createdAt:now(),
          updatedAt:now(),
          deleted:false,
          generationMode:'manual_rebuild',
          sourceSummaryIds:ids,
          sourceSummaryHash:hashText(ids.join('|')),
          ruleSnapshot:blockRuleSnapshot(block),
          version:VER,
          windowEligible:true,
          stale:false
        },0,s));
      }

      markDirty(s,'重建长期记忆');
      addLogToState(s,'长期记忆已重建','ok',startL+'L-'+endL+'L');
      await save(s);
      rebuilt++;
    }

    s=await load();
    await updateHistoryOverviewIfNeeded(s,'长期重建后更新历史总览',false);
    await save(s);

    s=await load();
    setTaskState(s,'sync_worldbook',{
      rangeText:fromL+'L - '+toL+'L',
      currentText:'正在同步世界书',
      allowPause:false,
      allowCancel:false
    });
    await save(s);

    try{
      await syncInjectBook(s,'rebuild-long-range');
      s=await load();
      finishTaskState(s,true,'长期记忆重建完成，新增/覆盖 '+rebuilt+' 条，跳过 '+skipped+' 条');
      await save(s);
      toast('长期记忆重建完成，共 '+rebuilt+' 条');
    }catch(syncErr){
      s=await load();
      logErrorToState(s,'世界书同步失败',syncErr,userErrorMessage(syncErr,'世界书同步'),{step:'worldbook_syncing'});
      finishTaskState(s,false,'长期记忆已重建，但世界书同步失败');
      await save(s);
      toast('长期记忆已重建，但世界书同步失败');
    }

    renderAll(true);
    return rebuilt;
  }catch(e){
    s=await load();
    finishTaskState(s,false,'重建长期记忆失败');
    logErrorToState(s,'长期记忆重建失败',e,userErrorMessage(e,'重建长期记忆'),{step:'longterm_generating'});
    await save(s);
    toast(userErrorMessage(e,'重建长期记忆'));
    renderAll(true);
    return null;
  }
}



async function rebuildHistoryOverview(){
  var s=await load();
  if(s.scan.busy){toast('当前有任务在运行');return null}
  if(s.runtimeTask&&s.runtimeTask.active){toast('已有任务正在执行');return null}

  var plan=buildInjectPlan(s);
  var desiredEnd=Number(plan.desiredHistoryEnd||0)||0;
  var rangeText=desiredEnd>0?('1L - '+desiredEnd+'L'):'当前无需生成';

  setTaskState(s,'rebuild_history',{
    rangeText:rangeText,
    currentText:'正在重建历史总览',
    allowPause:false,
    allowCancel:false
  });
  await save(s);
  renderAll(true);

  try{
    var changed=await updateHistoryOverviewIfNeeded(s,'手动重建历史总览',true);
    await save(s);

    if(changed){
      setTaskState(s,'sync_worldbook',{
        rangeText:rangeText,
        currentText:'正在同步世界书',
