function autoSummaryCheck(){
  if(app._summaryAutoChecking)return;
  app._summaryAutoChecking=true;
  Promise.resolve().then(async function(){
    try{
      if(!masterMemoEnabled())return;
      var s=await load();
            if(!s.meta.started)return;
      if(!s.settings.autoSummaryEnabled)return;

      if(s.scan.busy||s.scan.paused||s.scan.cancelRequested||s.scan.recoverable)return;

      if(s.scan.cooldownUntil&&now()<s.scan.cooldownUntil)return;
      var cur=await countAssistant(false);
      var interval=Math.max(8,Number(s.settings.summaryIntervalL||24)||24);
      var nextFrom=Math.max(1,(Number(s.progress.processedL||0)||0)+1);
      var nextTo=Math.min(cur,nextFrom+interval-1);
      if(nextTo-nextFrom+1<interval)return;
      await runSummary({manual:false,fromL:nextFrom,toL:nextTo});
    }catch(e){
      console.warn('[第五季果汁 auto summary]',e);
    }finally{
      app._summaryAutoChecking=false;
    }
  });
}

function startAutoSummaryTimer(){
  try{
    if(T[AUTO_TIMER_KEY])clearInterval(T[AUTO_TIMER_KEY]);
    T[AUTO_TIMER_KEY]=null;
    if(!masterMemoEnabled())return;
    T[AUTO_TIMER_KEY]=setInterval(function(){autoSummaryCheck()},60000);
    setTimeout(function(){autoSummaryCheck()},3000);
  }catch(e){console.warn('[第五季果汁 timer]',e)}
}

async function onMasterToggle(enabled){
  if(!enabled){
    try{if(T[AUTO_TIMER_KEY])clearInterval(T[AUTO_TIMER_KEY]);T[AUTO_TIMER_KEY]=null}catch(_timer){}
    try{await setMemoInjectBinding(false)}catch(_unbind){}
    try{close()}catch(_close){}
    return false;
  }
  try{await setMemoInjectBinding(true)}catch(_bind){}
  startAutoSummaryTimer();
  return true;
}

