async function findInjectBookByName(name){
  name=trim(name);
  if(!name||!T.tavo||!T.tavo.lorebook)return null;
  try{
    var found=await hostCall(function(){return T.tavo.lorebook.find(name,{match:'exact'})},'lorebook.find.memo',10000,{silent:true,fallback:[]});
    if(Array.isArray(found)&&found.length&&found[0]&&found[0].id!=null)return await hostCall(function(){return T.tavo.lorebook.get(found[0].id)},'lorebook.get.memo',12000,{silent:true,fallback:null});
  }catch(_1){}
  try{
    var all=await hostCall(function(){return T.tavo.lorebook.all()},'lorebook.all.memo',12000,{silent:true,fallback:[]});
    if(Array.isArray(all)){
      for(var i=0;i<all.length;i++){
        if(all[i]&&trim(all[i].name)===name)return await hostCall(function(){return T.tavo.lorebook.get(all[i].id)},'lorebook.get.memo',12000,{silent:true,fallback:null});
      }
    }
  }catch(_2){}
  return null;
}

function entryBase(identifier,name,content,enabled){
  return {
    identifier:String(identifier||''),
    name:String(name||'记忆条目'),
    content:String(content||''),
    enabled:enabled!==false,
    strategy:'constant',
    keywords:[],
    secondaryKeywords:[],
    secondaryKeywordStrategy:'none',
    scanDepth:2,
    caseSensitive:false,
    matchWholeWord:false,
    injectionPosition:'lorebookBefore',
    injectionDepth:4,
    injectionRole:'system',
    probability:100,
    sticky:0,
    cooldown:0,
    delay:0
  };
}

function historyOverviewDisplayTitle(hov){
  if(!hov)return '历史总览';
  return '历史总览｜'+(Number(hov.startL||1)||1)+'L - '+(Number(hov.endL||0)||0)+'L';
}
function summaryDisplayTitle(x){
  return '阶段总结｜'+(Number(x.startL||0)||0)+'L - '+(Number(x.endL||0)||0)+'L';
}
function longTermDisplayTitle(x){
  return '长期记忆｜'+(Number(x.startL||0)||0)+'L - '+(Number(x.endL||0)||0)+'L';
}
function preludeMemoryEntryContent(s){
  s=normalize(s||app.state||{});
  var pm=normalizePreludeMemory(s.preludeMemory);
  if(!pm.enabled||!pm.source)return'';
  var content=String(pm.source.content==null?'':pm.source.content);
  if(!trim(content))return'';
  return '【前情提要】\n\n以下是当前聊天开始前已经发生的记忆，请作为前情理解。\n后续记忆从当前聊天开始记录。\n\n'+content;
}
function pendingStatusText(v){
  var map={open:'待兑现',due_unconfirmed:'到期未确认',resolved_done:'已完成',resolved_missed:'已错过或未完成',rescheduled:'已改期',cancelled:'已取消',superseded:'已被覆盖',uncertain:'证据不足'};
  return map[trim(v)]||trim(v)||'待兑现';
}
function pendingEntryContent(s){
  s=normalize(s||app.state||{});  
  var list=safeArr(s.pendingThreads).map(normalizePendingThread).filter(function(x){return ['open','due_unconfirmed','rescheduled','uncertain'].indexOf(x.status)>=0});
  if(!list.length)return'';
  var lines=['【待解决事项】','以下事项来自阶段总结的结构化追踪。判断完成、错过或取消时，必须以当前聊天原文为准；没有提到不能判定没做。'];
  list.slice(-16).forEach(function(x){
    lines.push('- '+clip(x.title||'待解决事件',42)+'｜状态：'+pendingStatusText(x.status)+'｜来源：'+(Number(x.startL||0)||0)+'L-'+(Number(x.endL||0)||0)+'L｜'+clip(x.detail||'',140));
  });
  return lines.join('\n');
}
async function updatePendingThreadStatus(id,status,patch){
  id=mid(id);
  status=trim(status||'open');
  patch=patch&&typeof patch==='object'?patch:{};
  if(!id)return false;
  var s=await load();
  s.pendingThreads=safeArr(s.pendingThreads).map(normalizePendingThread);
  var found=false;
  s.pendingThreads=s.pendingThreads.map(function(x){
    if(!x||x.id!==id)return x;
    found=true;
    var next=normalizePendingThread(Object.assign({},x,patch,{status:status}));
    next.updatedAt=now();
    if(status==='resolved_done'||status==='resolved_missed'||status==='cancelled'||status==='superseded'){
      next.resolvedAt=now();
    }else{
      next.resolvedAt=0;
    }
    if(patch.note!=null)next.note=trim(patch.note||'');
    return next;
  });
  if(!found)return false;
  markDirty(s,'更新待解决事项');
  addLogToState(s,'待解决事项已更新','ok',id,null,{step:'pending_update',status:status,pendingId:id});
  await save(s);
  try{await syncInjectBook(s,'pending-thread-update')}catch(syncErr){markSyncError(s,syncErr.message||'同步失败');await save(s)}
  return true;
}

async function ensureInjectBook(s){
  s=s||await load();
  if(!T.tavo||!T.tavo.lorebook)throw new Error('当前宿主不支持世界书');
  var names=await getNamesCached();
  var chatId=s.chatId||await currentChatId();
  var shortId=String(chatId||'').slice(-3);var targetName='记忆 · '+(names.charName||'角色')+(shortId?' · #'+shortId:'');
  if(s.sync&&s.sync.injectBookId){
    try{
      var existing=await hostCall(function(){return T.tavo.lorebook.get(s.sync.injectBookId)},'lorebook.get.bound',12000,{silent:true,fallback:null});
      if(existing)return existing;
    }catch(_1){}
  }
  var book=await findInjectBookByName(targetName);
  if(!book){
    var created=await hostCall(function(){return T.tavo.lorebook.create({
      name:targetName,
     entries:[]

    })},'lorebook.create.memo',15000);
    book=typeof created==='object'&&created&&created.id!=null?created:await hostCall(function(){return T.tavo.lorebook.get(created)},'lorebook.get.created',12000);
  }
  s.sync=s.sync||{};
  s.sync.injectBookId=book&&book.id||null;
  await save(s);
  return book;
}

function buildInjectEntries(s){
  var plan=buildInjectPlan(s);
  var out=[];
  var preludeContent=preludeMemoryEntryContent(s);
  if(preludeContent){
    out.push(entryBase(
      'memo_prelude_memory',
      '前情提要',
      preludeContent,
      true
    ));
  }

  var pendingContent=pendingEntryContent(s);
  if(pendingContent){
    out.push(entryBase(
      'memo_pending_state',
      '待解决事项',
      pendingContent,
      true
    ));
  }

  if(plan.desiredHistoryEnd>0&&s.historyOverview&&Number(s.historyOverview.endL||0)===Number(plan.desiredHistoryEnd||0)){
    out.push(entryBase(
      'memo_history_overview',
      historyOverviewDisplayTitle(s.historyOverview),
      '【历史总览】\n'+trim(s.historyOverview.content||''),
      true
    ));
  }

  plan.injectLongs.forEach(function(x){
    out.push(entryBase(
      'memo_long_'+x.id,
      longTermDisplayTitle(x),
      '【长期记忆】\n'+trim(x.content||''),
      true
    ));
  });

  plan.injectShorts.forEach(function(x){
    out.push(entryBase(
      'memo_short_'+x.id,
      summaryDisplayTitle(x),
      '【阶段总结】\n'+trim(x.summary||x.content||''),
      true
    ));
  });

  return out;
}

function filterNonMemoEntries(entries){
  return safeArr(entries).filter(function(e){
    var id=String(e&&e.identifier||'');
    if(id==='memo_root')return false;
    if(id==='memo_history_overview')return false;
    if(id==='memo_prelude_memory')return false;
    if(id==='memo_pending_state')return false;
    if(isRemovedMemoIdentifier(id))return false;
    if(/^memo_long_/.test(id))return false;
    if(/^memo_short_/.test(id))return false;
    if(id==='fs_root')return false;
    if(id==='fs_history_overview')return false;
    if(id==='fs_pending_state')return false;
    if(/^fs_long_/.test(id))return false;
    if(/^fs_short_/.test(id))return false;
    return true;
  });
}
function memoEntriesOnly(entries){
  return safeArr(entries).filter(function(e){
    var id=String(e&&e.identifier||'');
    return id==='memo_history_overview'||id==='memo_prelude_memory'||id==='memo_pending_state'||/^memo_long_/.test(id)||/^memo_short_/.test(id);
  });
}

function memoEntriesSignature(entries){
  return memoEntriesOnly(entries).map(function(e){
    return JSON.stringify([
      String(e&&e.identifier||''),
      String(e&&e.name||''),
      String(e&&e.content||''),
      !!(e&&e.enabled)
    ]);
  }).sort().join('\n');
}

async function syncInjectBook(s,reason){
  s=s||await load();
  if(!isSyncReady(s)){
    markSyncError(s,'等待初始化向导完成');
    addLogToState(s,'世界书同步已等待','ok','请先完成初始化选择、锚定和前情提要处理');
    await save(s);
    return null;
  }
  var book=await ensureInjectBook(s);
  if(!book)throw new Error('无法创建或获取注入书');

  var startText='世界书同步';
  var startDetail='正在同步世界书';
  addLogToState(s,startText,'running',startDetail,null,{step:'worldbook_syncing'});

  var entries=buildInjectEntries(s);
  var keep=filterNonMemoEntries(book.entries);
  entries.forEach(function(e){keep.push(e)});

  book.entries=keep;
  book.name=book.name||'记忆系统注入书';

  try{
    await hostCall(function(){return T.tavo.lorebook.update(book)},'lorebook.update.memo',20000);
  }catch(e){
    var treatedOk=false;

    if(classifyError(e)==='api_timeout' && book && book.id!=null){
      try{
        await new Promise(function(resolve){setTimeout(resolve,800)});
        var fresh=await hostCall(function(){return T.tavo.lorebook.get(book.id)},'lorebook.get.verify',12000,{silent:true,fallback:null});
        if(memoEntriesSignature(fresh.entries)===memoEntriesSignature(keep)){
          treatedOk=true;
        }
      }catch(_verifyErr){}
    }

    if(treatedOk){
      markSyncOk(s);
      resolveRunningLog(s,startText,startDetail,'世界书同步完成','ok','共 '+entries.length+' 条注入');
      await save(s);
      try{await setMemoInjectBinding(true,s)}catch(_bind){}
      return book;
    }

    resolveRunningLog(s,startText,startDetail,'世界书同步失败','err',userErrorMessage(e,'世界书同步'),e);
    throw e;
  }

  markSyncOk(s);
  resolveRunningLog(s,startText,startDetail,'世界书同步完成','ok','共 '+entries.length+' 条注入');
  await save(s);
  try{await setMemoInjectBinding(true,s)}catch(_bind){}
  return book;
}



