async function rerollSummary(id){
  var s=await load();
  var x=safeArr(s.summaries).find(function(v){return v.id===id});
  if(!x||x.deleted){
    toast('找不到总结');
    return false;
  }

  if(s.scan&&s.scan.busy){
    toast('当前有任务在运行');
    return false;
  }
  if(s.runtimeTask&&s.runtimeTask.active){
    toast('已有任务正在执行');
    return false;
  }

  var bundle=await collectRange(x.startL,x.endL);
  if(!bundle.messages.length){
    toast('无可重抽消息');
    return false;
  }

  toast('正在重抽总结...');

  try{
    var d=await generateSummaryData(bundle,s,{
      fallbackTitle:'阶段总结 '+x.startL+'L-'+x.endL+'L',
      abortKey:'_scanAbort',
      retries:2,
      temperature:0.55
    });

    var newTitle=clip(trim(d.title||''),42);
    var newSummary=trim(d.summary||'');

    if(!newSummary){
      addLogToState(s,'短期总结重抽失败','err',x.startL+'L-'+x.endL+'L · 返回内容为空');
      await save(s);
      toast('重抽失败：返回为空');
      renderAll(true);
      return false;
    }

    if(!newTitle || sig(newTitle)==='标题' || sig(newTitle)==='【标题】' || sig(newTitle)==='阶段总结'){
      newTitle=clip(extractSectionTitle(newSummary)||('阶段总结 '+x.startL+'L-'+x.endL+'L'),42);
    }

    // 这里不再判断是否变化，不再比较 hash。
    // 重抽就是直接覆盖。
    pushRevision(x);
    x.title=newTitle;
    x.summary=newSummary;
    x.content=newSummary;
    x.startMessageId=assistantMessageIdForL(bundle,x.startL)||x.startMessageId||'';
    x.endMessageId=assistantMessageIdForL(bundle,x.endL)||x.endMessageId||'';
    x.updatedAt=now();
    x.deleted=false;
    x.sourceHash=hashText(newSummary);
    x.generationMode='reroll_summary';

    markDependentLongTermsStale(s,[x.id],'短期总结重抽导致长期待重建');
    markDirty(s,'重抽短期总结');

    addLogToState(s,'短期总结已重抽','ok',x.startL+'L-'+x.endL+'L · 已直接覆盖');
    await save(s);

    try{
      await syncInjectBook(s,'reroll-summary');
      toast('重抽完成，已覆盖并同步世界书');
    }catch(syncErr){
      markSyncError(s,syncErr&&syncErr.message||'同步失败');
      logErrorToState(s,'世界书同步失败',syncErr,userErrorMessage(syncErr,'世界书同步'),{step:'worldbook_syncing'});
      await save(s);
      toast('重抽完成，但世界书同步失败');
    }

    renderAll(true);
    return true;

  }catch(e){
    logErrorToState(s,'短期总结重抽失败',e,userErrorMessage(e,'重抽短期总结'),{step:'summary_generating'});
    await save(s);
    toast(userErrorMessage(e,'重抽短期总结'));
    renderAll(true);
    return false;
  }
}




