async function fetchApiModels(){
  var s=await load();
  var cfg=effectiveApiSettings(s);
  var base=trim(cfg.apiBaseUrl||'');
  var key=trim(cfg.apiKey||'');

  if(!base||!key){
    addLogToState(s,'获取模型列表失败','err','请先在设置里保存接口地址和密钥',null,{step:'requesting_model',code:'api_config_missing'});
    await save(s);
    toast('请先在设置里保存接口地址和密钥');
    renderAll(true);
    return [];
  }

  var url=base.replace(/\/+$/,'');
  if(/\/v1$/i.test(url)) url=url+'/models';
  else if(/\/v1\/chat\/completions$/i.test(url)) url=url.replace(/\/chat\/completions$/i,'/models');
  else url=url+'/models';

  try{
    addLogToState(s,'获取模型列表','running','正在向接口请求模型列表',null,{step:'requesting_model'});
    await save(s);

    var r=await fetch(url,{
      method:'GET',
      headers:{
        'Content-Type':'application/json',
        'Authorization':'Bearer '+key
      }
    });

    if(!r.ok){
      var bodyText='',bodyObj=null;
      try{bodyText=await r.text()}catch(_bodyErr){bodyText=''}
      if(bodyText){try{bodyObj=JSON.parse(bodyText)}catch(_jsonErr){}}
      throw apiError(r.status,bodyText,bodyObj);
    }

    var d=await r.json();
    var list=safeArr(d&&d.data).map(function(x){
      return x&&x.id?String(x.id):'';
    }).filter(Boolean);

    if(!list.length)throw new Error('接口未返回可用模型');

    list=list.sort();

    saveGlobalConfig({activeApiProfileId:cfg.activeApiProfileId,models:list});
    resolveRunningLog(s,'获取模型列表','正在向接口请求模型列表','获取模型列表成功','ok','共 '+list.length+' 个模型');
    await save(s);
    return list;
  } catch(e){
  var closed=resolveRunningLog(s,'获取模型列表','正在向接口请求模型列表','获取模型列表失败','err',userErrorMessage(e,'获取模型列表'),e);
  if(!closed){
    addLogToState(s,'获取模型列表失败','err',userErrorMessage(e,'获取模型列表'),e,{
      step:'requesting_model',
      code:classifyError(e),
      devDetail:String(e&&e.devDetail||e&&e.responseBody||e&&e.message||e||'')
    });
  }
  await save(s);
  toast(userErrorMessage(e,'获取模型列表'));
  renderAll(true);
  return [];
}

}



