async function reanchorToCurrentFloor(){
  var s=await load();
  if(!s.meta.started){
    toast('请先在首页点“从当前楼层后开始记录”');
    return null;
  }
  if((s.scan&&s.scan.busy)||(s.runtimeTask&&s.runtimeTask.active)){
    toast('当前有任务在运行，请先完成、暂停或重置任务状态');
    return null;
  }

  var currentL=await countAssistant(true);
  refreshMemoFloorsByMessageIds(s,null,null,app._lastMsgCount||0);
  var removedSummaryIds={};
  var removedSummaryCount=0;
  var removedLongCount=0;
  var removedGapCount=0;
  var clearedHistory=0;

  safeArr(s.summaries).forEach(function(x){
    if(x && !x.deleted && Number(x.endL||0)>currentL){
      x.deleted=true;
      x.updatedAt=now();
      removedSummaryIds[x.id]=true;
      removedSummaryCount++;
    }
  });

  var activeSummaryIdMap={};
  activeSummariesSorted(s).forEach(function(x){
    activeSummaryIdMap[x.id]=true;
  });

  safeArr(s.longTerms).forEach(function(x){
    if(!x||x.deleted)return;
    var refs=safeArr(x.sourceSummaryIds);
    var hitRemoved=refs.some(function(id){ return removedSummaryIds[id]; });
    var missingRef=refs.length?refs.some(function(id){ return !activeSummaryIdMap[id]; }):false;
    if(Number(x.endL||0)>currentL || hitRemoved || missingRef){
      x.deleted=true;
      x.updatedAt=now();
      removedLongCount++;
    }
  });

  if(s.historyOverview){
    var hovRefs=safeArr(s.historyOverview.sourceSummaryIds);
    var hovHitRemoved=hovRefs.some(function(id){ return removedSummaryIds[id]; });
    if(Number(s.historyOverview.endL||0)>currentL || hovHitRemoved){
      s.historyOverview=null;
      clearedHistory=1;
    }
  }

  var beforeGapCount=safeArr(s.failedRanges).length;
  s.failedRanges=safeArr(s.failedRanges).filter(function(x){
    return x && Number(x.endL||0)<=currentL;
  });
  removedGapCount=beforeGapCount-s.failedRanges.length;

  if(Number(s.progress.baselineL||0)>currentL){
    s.progress.baselineL=currentL;
  }

  setScanState(s,null,false);
  s.runtimeTask=null;
  s.progress.currentAssistantCount=currentL;
  updateProgressFromSummaries(s);
  detectUnrecordedRanges(s,currentL);

  markDirty(s,'重新锚定当前楼层');
  addLogToState(
    s,
    '重新锚定当前楼层',
    'ok',
    '当前 '+currentL+'L；清理短期 '+removedSummaryCount+' 条，长期 '+removedLongCount+' 条，历史总览 '+clearedHistory+' 条，缺口 '+removedGapCount+' 条。'
  );

  await save(s);

  try{
    await syncInjectBook(s,'reanchor-current-floor');
  }catch(syncErr){
    markSyncError(s,syncErr&&syncErr.message||'同步失败');
    logErrorToState(s,'世界书同步失败',syncErr,userErrorMessage(syncErr,'世界书同步'),{step:'worldbook_syncing'});
    await save(s);
  }

  toast('已按当前 '+currentL+'L 重新锚定');
  renderAll(true);

  return {
    currentL:currentL,
    removedSummaryCount:removedSummaryCount,
    removedLongCount:removedLongCount,
    clearedHistory:clearedHistory,
    removedGapCount:removedGapCount
  };
}

